{
  "name": "Sky-High Parkour: Happy Hops",
  "description": "A vibrant, light-hearted 2D parkour game featuring a dreamy cloudscape. Navigate through floating islands using unique controls (W/S for movement, Space to jump) and receive encouragement from your AI Spirit Guide."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Vector2D {
  x: number;
  y: number;
}

export enum PlatformType {
  NORMAL = 'NORMAL',
  BOUNCY = 'BOUNCY',
  MOVING = 'MOVING',
  FRAGILE = 'FRAGILE',
  FINISH = 'FINISH'
}

export interface Platform {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  type: PlatformType;
  color: string;
  moveRange?: number;
  moveSpeed?: number;
  initialX?: number;
}

export interface Player {
  pos: Vector2D;
  vel: Vector2D;
  width: number;
  height: number;
  isGrounded: boolean;
  jumpCount: number;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export interface GameState {
  player: Player;
  platforms: Platform[];
  particles: Particle[];
  cameraX: number;
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  distanceReached: number;
}

export interface Encouragement {
  text: string;
  mood: 'happy' | 'motivational' | 'funny';
}

export const GRAVITY = 0.5;
export const JUMP_FORCE = -12;
export const MOVE_SPEED = 0.8;
export const MAX_SPEED = 7;
export const FRICTION = 0.85;
export const WORLD_WIDTH = 10000;
export const WORLD_HEIGHT = 600;

export const COLORS = {
  SKY: '#bae6fd', // sky-200
  CLOUD: '#ffffff',
  GRASS: '#4ade80', // green-400
  BOUNCY: '#f472b6', // pink-400
  MOVING: '#60a5fa', // blue-400
  PLAYER: '#fbbf24', // amber-400
  FINISH: '#a855f7', // purple-500
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getEncouragement(context: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Context: The player is playing a happy 2D parkour game called 'Sky-High Hops'. ${context}. Give a very short, cheerful, and punny sentence of encouragement. No more than 10 words.`,
      config: {
        maxOutputTokens: 50,
        temperature: 0.9,
      }
    });
    return response.text.trim() || "Keep hopping, superstar!";
  } catch (error) {
    console.error("Gemini failed:", error);
    return "You're doing great! Keep going!";
  }
}

import React from 'react';

