const UIOverlay: React.FC<UIOverlayProps> = ({ score, isGameOver, isGameWon, encouragement, onRestart }) => {
  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-8 font-['Quicksand']">
      {/* Top Bar */}
      <div className="flex justify-between items-start">
        <div className="bg-white/80 backdrop-blur-sm px-6 py-3 rounded-2xl shadow-lg border-b-4 border-sky-300">
