          <p className="text-gray-600 font-semibold text-lg">Distance: {Math.floor(score / 10)}m</p>
        </div>

        <div className="bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-md border-r-4 border-amber-300 max-w-xs transition-all duration-300">
