      {/* Controls Help */}
      {!isGameOver && !isGameWon && (
        <div className="flex justify-center mb-4">
          <div className="bg-black/20 backdrop-blur-sm text-white px-4 py-2 rounded-full text-sm font-bold animate-pulse">
            [W] FORWARD • [S] BACKWARD • [SPACE] JUMP
          </div>
