      )}

      {/* Game States */}
      {(isGameOver || isGameWon) && (
        <div className="absolute inset-0 bg-white/40 backdrop-blur-md flex items-center justify-center pointer-events-auto">
          <div className="bg-white p-10 rounded-3xl shadow-2xl border-8 border-sky-100 text-center transform transition-all animate-in zoom-in duration-300">
            {isGameWon ? (
              <>
                <h2 className="text-6xl font-['Fredoka_One'] text-purple-500 mb-4">VICTORY! 🌈</h2>
