export default UIOverlay;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, MOVE_SPEED, MAX_SPEED, FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: { ...INITIAL_PLAYER },
    platforms: [],
    particles: [],
    cameraX: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
  });

  const [encouragement, setEncouragement] = useState("Ready for a sky-high adventure?");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});

  // Level Generation
  const generateLevel = useCallback(() => {
    const platforms: Platform[] = [
      { id: 'start', x: 0, y: 450, width: 300, height: 100, type: PlatformType.NORMAL, color: COLORS.GRASS }
    ];

    let currentX = 400;
    for (let i = 0; i < 50; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = 120 + Math.random() * 80;
      let height = 30;
      let y = 150 + Math.random() * 300;
      let moveRange = 0;
      let moveSpeed = 0;

      if (typeSeed > 0.85) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.7) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * 100;
        moveSpeed = 1 + Math.random() * 2;
      }

      platforms.push({
        id: `p-${i}`,
        x: currentX,
        y,
        width,
        height,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: currentX
      });

      currentX += 200 + Math.random() * 150;
    }

    platforms.push({
      id: 'finish',
      x: currentX + 100,
      y: 200,
      width: 400,
      height: 400,
      type: PlatformType.FINISH,
      color: COLORS.FINISH
    });

    return platforms;
  }, []);

  const resetGame = useCallback(() => {
    setGameState({
      player: { ...INITIAL_PLAYER },
      platforms: generateLevel(),
      particles: [],
      cameraX: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
    });
    setEncouragement("Let's go again! Higher this time!");
  }, [generateLevel]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 10000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  };

  const handleKeyDown = (e: KeyboardEvent) => {
    keys.current[e.code] = true;
  };

  const handleKeyUp = (e: KeyboardEvent) => {
    keys.current[e.code] = false;
  };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon) return prev;

      const newPlayer = { ...prev.player };
      const newParticles = [...prev.particles];

      // Input handling: W is forward (right), S is backward (left)
      if (keys.current['KeyW']) {
        newPlayer.vel.x += MOVE_SPEED;
      } else if (keys.current['KeyS']) {
        newPlayer.vel.x -= MOVE_SPEED;
      } else {
        newPlayer.vel.x *= FRICTION;
      }

      if (keys.current['Space'] && newPlayer.isGrounded) {
        newPlayer.vel.y = JUMP_FORCE;
        newPlayer.isGrounded = false;
        // Jump particles
        for (let i = 0; i < 5; i++) {
          newParticles.push({
            x: newPlayer.pos.x + newPlayer.width / 2,
            y: newPlayer.pos.y + newPlayer.height,
            vx: (Math.random() - 0.5) * 5,
            vy: Math.random() * 2,
            life: 1.0,
            color: COLORS.CLOUD,
            size: 4 + Math.random() * 4
          });
        }
      }

      // Cap speed
      newPlayer.vel.x = Math.max(-MAX_SPEED, Math.min(MAX_SPEED, newPlayer.vel.x));

      // Physics
      newPlayer.vel.y += GRAVITY;
      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      // Platform Collisions
      let grounded = false;
      const updatedPlatforms = prev.platforms.map(p => {
        // Moving platform logic
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          return { ...p, x: p.initialX + offsetX };
        }
        return p;
      });

      for (const p of updatedPlatforms) {
        // Simple AABB Collision
        if (
          newPlayer.pos.x < p.x + p.width &&
          newPlayer.pos.x + newPlayer.width > p.x &&
          newPlayer.pos.y + newPlayer.height > p.y &&
          newPlayer.pos.y + newPlayer.height < p.y + p.height + 15 &&
          newPlayer.vel.y >= 0
        ) {
          // Landing
          if (p.type === PlatformType.FINISH) {
            setGameState(s => ({ ...s, isGameWon: true }));
            updateGeminiEncouragement("The player reached the rainbow finish line!");
          }

          newPlayer.pos.y = p.y - newPlayer.height;
          newPlayer.vel.y = p.type === PlatformType.BOUNCY ? JUMP_FORCE * 1.8 : 0;
          grounded = true;

          if (p.type === PlatformType.BOUNCY) {
            // Bounce particles
            for (let i = 0; i < 8; i++) {
              newParticles.push({
                x: newPlayer.pos.x + newPlayer.width / 2,
                y: newPlayer.pos.y + newPlayer.height,
                vx: (Math.random() - 0.5) * 10,
                vy: -Math.random() * 5,
                life: 1.0,
                color: COLORS.BOUNCY,
                size: 3 + Math.random() * 3
              });
            }
          }
        }
      }

      newPlayer.isGrounded = grounded;

      // Camera Follow (Smoothly interpolate)
      const targetCameraX = newPlayer.pos.x - 300;
      const cameraX = prev.cameraX + (targetCameraX - prev.cameraX) * 0.1;

      // Game Over Check
      let isGameOver = prev.isGameOver;
      if (newPlayer.pos.y > WORLD_HEIGHT + 100) {
        isGameOver = true;
        updateGeminiEncouragement("The player fell off a platform into the clouds.");
      }

      // Particles Update
      const filteredParticles = newParticles.map(part => ({
        ...part,
        x: part.x + part.vx,
        y: part.y + part.vy,
        life: part.life - 0.02
      })).filter(part => part.life > 0);

      const score = Math.max(prev.score, newPlayer.pos.x);

      // Random encouragement while playing
      if (Math.random() < 0.001) {
        updateGeminiEncouragement("The player is successfully jumping through a beautiful pastel level.");
      }

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        score,
        isGameOver
      };
    });
  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        encouragement={encouragement}
        onRestart={resetGame}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS, WORLD_HEIGHT } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Set canvas size to full window
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX } = gameState;

    // 1. Draw Background (Parallax)
    // Sky gradient
    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, '#7dd3fc'); // sky-300
    gradient.addColorStop(1, '#e0f2fe'); // sky-50
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax Clouds
    ctx.save();
    ctx.translate(-cameraX * 0.3, 0);
    drawCloud(ctx, 200, 100, 1.2);
    drawCloud(ctx, 800, 150, 0.8);
    drawCloud(ctx, 1500, 80, 1.5);
    drawCloud(ctx, 2200, 120, 1.0);
    drawCloud(ctx, 3000, 50, 0.9);
    ctx.restore();

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, 0);

    // Platforms
    platforms.forEach(p => {
      // Draw platform shadow
      ctx.fillStyle = 'rgba(0,0,0,0.1)';
      ctx.beginPath();
      ctx.roundRect(p.x + 4, p.y + 4, p.width, p.height, 15);
      ctx.fill();

      // Platform body
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 15);
      ctx.fill();

      // Platform details based on type
      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (p.type === PlatformType.MOVING) {
        ctx.strokeStyle = '#dbeafe';
        ctx.lineWidth = 3;
        ctx.setLineDash([5, 5]);
        ctx.stroke();
        ctx.setLineDash([]);
      } else if (p.type === PlatformType.FINISH) {
        // Rainbow effect for finish
        const rainbow = ctx.createLinearGradient(p.x, 0, p.x + p.width, 0);
        rainbow.addColorStop(0, '#f87171');
        rainbow.addColorStop(0.2, '#fb923c');
        rainbow.addColorStop(0.4, '#facc15');
        rainbow.addColorStop(0.6, '#4ade80');
        rainbow.addColorStop(0.8, '#60a5fa');
        rainbow.addColorStop(1, '#a78bfa');
        ctx.fillStyle = rainbow;
        ctx.fillRect(p.x, p.y - 10, p.width, 10);
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player
    // Shadow
    ctx.fillStyle = 'rgba(0,0,0,0.15)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4, player.pos.y + 4, player.width, player.height, 10);
    ctx.fill();

    // Body
    ctx.fillStyle = COLORS.PLAYER;
    ctx.beginPath();
    ctx.roundRect(player.pos.x, player.pos.y, player.width, player.height, 10);
    ctx.fill();

    // Eyes
    ctx.fillStyle = '#fff';
    const eyeSize = 10;
    const eyeOffsetX = player.vel.x > 0 ? 5 : (player.vel.x < 0 ? -5 : 0);
    ctx.fillRect(player.pos.x + 8 + eyeOffsetX, player.pos.y + 10, eyeSize, eyeSize);
    ctx.fillRect(player.pos.x + 22 + eyeOffsetX, player.pos.y + 10, eyeSize, eyeSize);
    ctx.fillStyle = '#333';
    ctx.fillRect(player.pos.x + 11 + eyeOffsetX, player.pos.y + 13, 4, 4);
    ctx.fillRect(player.pos.x + 25 + eyeOffsetX, player.pos.y + 13, 4, 4);

    // Mouth
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2;
    ctx.beginPath();
    if (player.vel.y < 0) { // Jumping
      ctx.arc(player.pos.x + 20, player.pos.y + 30, 5, 0, Math.PI);
    } else { // Normal/Falling
      ctx.arc(player.pos.x + 20, player.pos.y + 25, 5, 0, Math.PI, false);
    }
    ctx.stroke();

    ctx.restore();

  }, [gameState]);

  // Helper to draw a fluffy cloud
  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    ctx.arc(x, y, 30 * scale, 0, Math.PI * 2);
    ctx.arc(x + 40 * scale, y, 50 * scale, 0, Math.PI * 2);
    ctx.arc(x + 90 * scale, y, 35 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  return (
    <canvas 
      ref={canvasRef} 
      className="block w-full h-full cursor-none"
    />
  );
};

export default GameCanvas;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getEncouragement(context: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Context: The player is playing a happy 2D parkour game called 'Sky-High Hops'. ${context}. Give a very short, cheerful, and punny sentence of encouragement. No more than 10 words.`,
      config: {
        maxOutputTokens: 50,
        temperature: 0.9,
      }
    });

    // Safely access the text property as it can be undefined if the response is blocked or empty
    const text = response.text?.trim();
    return text || "Keep hopping, superstar!";
  } catch (error) {
    console.error("Gemini failed:", error);
    return "You're doing great! Keep going!";
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, MOVE_SPEED, MAX_SPEED, FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: { ...INITIAL_PLAYER },
    platforms: [],
    particles: [],
    cameraX: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
  });

  const [encouragement, setEncouragement] = useState("Ready for a sky-high adventure?");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);

  // Level Generation
  const generateLevel = useCallback(() => {
    const platforms: Platform[] = [
      { id: 'start', x: 0, y: 450, width: 300, height: 100, type: PlatformType.NORMAL, color: COLORS.GRASS }
    ];

    let currentX = 400;
    for (let i = 0; i < 50; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = 120 + Math.random() * 80;
      let height = 30;
      let y = 150 + Math.random() * 300;
      let moveRange = 0;
      let moveSpeed = 0;

      if (typeSeed > 0.85) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.7) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * 100;
        moveSpeed = 1 + Math.random() * 2;
      }

      platforms.push({
        id: `p-${i}`,
        x: currentX,
        y,
        width,
        height,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: currentX
      });

      currentX += 200 + Math.random() * 150;
    }

    platforms.push({
      id: 'finish',
      x: currentX + 100,
      y: 200,
      width: 400,
      height: 400,
      type: PlatformType.FINISH,
      color: COLORS.FINISH
    });

    return platforms;
  }, []);

  const resetGame = useCallback(() => {
    setGameState({
      player: { ...INITIAL_PLAYER },
      platforms: generateLevel(),
      particles: [],
      cameraX: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
    });
    setEncouragement("Let's go again! Higher this time!");
  }, [generateLevel]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 10000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  // Handle pending encouragement requests outside of the game loop
  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => {
    keys.current[e.code] = true;
  };

  const handleKeyUp = (e: KeyboardEvent) => {
    keys.current[e.code] = false;
  };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
