export interface Player {
  pos: Vector2D;
  vel: Vector2D;
  width: number;
  height: number;
  isGrounded: boolean;
  jumpCount: number;
  isWallSliding: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export interface GameState {
  player: Player;
  platforms: Platform[];
  particles: Particle[];
  cameraX: number;
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  distanceReached: number;
}

export interface Encouragement {
  text: string;
  mood: 'happy' | 'motivational' | 'funny';
}

export const GRAVITY = 0.5;
export const JUMP_FORCE = -12;
export const WALL_JUMP_FORCE_X = 8;
export const WALL_JUMP_FORCE_Y = -10;
export const MOVE_SPEED = 0.8;
export const MAX_SPEED = 8;
export const FRICTION = 0.85;
export const WORLD_WIDTH = 2000000; // Expanded for 1,000,000 score goal
export const WORLD_HEIGHT = 800;

export const COLORS = {
  SKY: '#bae6fd', 
  CLOUD: '#ffffff',
  GRASS: '#4ade80',
  BOUNCY: '#f472b6',
  MOVING: '#60a5fa',
  FRAGILE: '#fb923c', // orange-400
  BOOSTER: '#a855f7', // purple-500
  PLAYER: '#fbbf24',
  FINISH: '#ef4444', // red-500
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, WALL_JUMP_FORCE_X, WALL_JUMP_FORCE_Y, MOVE_SPEED, MAX_SPEED, FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
  });

  const [encouragement, setEncouragement] = useState("One million points awaits! Start hopping!");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number) => {
    const newPlatforms: Platform[] = [];
    const MAX_VERTICAL_UP = 110;
    const MAX_VERTICAL_DOWN = 180;

    let lastX = startX;
    let lastY = 450;
    let lastWidth = 300;

    // If starting fresh, add the grass platform
    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 300, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 300;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = 100 + Math.random() * 100;
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);
      nextY = Math.max(150, Math.min(550, nextY));

      const yDiff = lastY - nextY;
      let maxGap = 240; 
      if (yDiff > 50) maxGap = 160; 
      const gap = 80 + Math.random() * (maxGap - 80);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      if (typeSeed > 0.92) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.84) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * 100;
        moveSpeed = 1.2 + Math.random() * 1.5;
        nextX += moveRange / 2;
      } else if (typeSeed > 0.76) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = 40; // frames
      } else if (typeSeed > 0.70) {
        type = PlatformType.BOOSTER;
        color = COLORS.BOOSTER;
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 30,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
      lastWidth = width;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const resetGame = useCallback(() => {
    keys.current = {};
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const initialPlatforms = generatePlatforms(0, 30);

    setGameState({
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
    });
    setEncouragement("1,000,000 points is the goal. Go!");
  }, [generatePlatforms]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 12000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon) return prev;

      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;

      // Infinite level generation
      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 2000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 20);
        newPlatformsList = [...newPlatformsList, ...appended];
        // Garbage collect platforms far behind
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 500);
      }

      // Input handling
      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * MOVE_SPEED;
      } else {
        newPlayer.vel.x *= FRICTION;
      }

      // Physics update
      newPlayer.vel.y += GRAVITY;
      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      // Cap speed
      newPlayer.vel.x = Math.max(-MAX_SPEED * 2, Math.min(MAX_SPEED * 2, newPlayer.vel.x));

      // Wall Sliding & Jumping Logic
      let touchingWall = false;
      let wallDirection = 0; // 1 for right, -1 for left

      // Collision loop
      let grounded = false;
      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        // Moving platform
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        // Fragile decay
        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        // Horizontal wall collision detection for wall jumps
        const horizontalOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const verticalOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        if (verticalOverlap && !grounded) {
          // Check if hitting side
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 10) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 10) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        // Ground check (Standard top collision)
        if (
          horizontalOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = JUMP_FORCE * 1.7;
            for (let i = 0; i < 6; i++) {
              newParticles.push({
                x: newPlayer.pos.x + newPlayer.width / 2, y: newPlayer.pos.y + newPlayer.height,
                vx: (Math.random() - 0.5) * 8, vy: -Math.random() * 4,
                life: 1.0, color: COLORS.BOUNCY, size: 4
              });
            }
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 25; // Massive forward boost
             newPlayer.vel.y = -5;
             for (let i = 0; i < 10; i++) {
                newParticles.push({
                  x: newPlayer.pos.x, y: newPlayer.pos.y + 20,
                  vx: -Math.random() * 10, vy: (Math.random() - 0.5) * 5,
                  life: 1.0, color: COLORS.BOOSTER, size: 5
                });
             }
          } else {
            newPlayer.vel.y = 0;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          grounded = true;
        }

        return currentP;
      });

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = 2; // Slide down slowly
      }

      // Jump Logic
      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = JUMP_FORCE;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; // Prevent auto-rejump
        } else if (newPlayer.isWallSliding) {
          // Wall Jump
          newPlayer.vel.y = WALL_JUMP_FORCE_Y;
          newPlayer.vel.x = -wallDirection * WALL_JUMP_FORCE_X;
          keys.current['Space'] = false;
          for (let i = 0; i < 5; i++) {
            newParticles.push({
              x: newPlayer.pos.x + (wallDirection === 1 ? newPlayer.width : 0),
              y: newPlayer.pos.y + 20,
              vx: wallDirection * 3, vy: -2,
              life: 1.0, color: '#fff', size: 3
            });
          }
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - 300) - prev.cameraX) * 0.1;
      const score = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > WORLD_HEIGHT + 200) {
        isGameOver = true;
        pendingEncouragementContext.current = `Oh no! Fell at ${score} points.`;
      }

      if (score >= 1000000) {
        isGameWon = true;
        pendingEncouragementContext.current = "THE IMPOSSIBLE REACHED! 1,000,000 POINTS!";
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        score,
        isGameOver,
        isGameWon
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        encouragement={encouragement}
        onRestart={resetGame}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS, WORLD_HEIGHT } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, score } = gameState;

    // 1. Draw Background (Altitude-based Parallax)
    const skyTransition = Math.min(1, score / 500000);
    const topColor = lerpColor('#7dd3fc', '#1e293b', skyTransition);
    const bottomColor = lerpColor('#e0f2fe', '#334155', skyTransition);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax Clouds
    ctx.save();
    ctx.translate(-cameraX * 0.3, 0);
    for (let i = 0; i < 10; i++) {
        drawCloud(ctx, i * 800 + 200, 100 + (i % 3) * 50, 0.8 + (i % 2) * 0.5);
    }
    ctx.restore();

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, 0);

    // Platforms
    platforms.forEach(p => {
      // Don't draw if already decayed
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Shadow
      ctx.fillStyle = 'rgba(0,0,0,0.1)';
      ctx.beginPath();
      ctx.roundRect(p.x + 4, p.y + 4, p.width, p.height, 10);
      ctx.fill();

      // Body
      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = p.decay / 40;
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 10);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Type details
      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 2;
        ctx.stroke();
      } else if (p.type === PlatformType.BOOSTER) {
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        // Draw arrows on booster
        for(let i=0; i<3; i++) {
          ctx.beginPath();
          ctx.moveTo(p.x + 20 + i*30, p.y + 5);
          ctx.lineTo(p.x + 40 + i*30, p.y + 15);
          ctx.lineTo(p.x + 20 + i*30, p.y + 25);
          ctx.fill();
        }
      } else if (p.type === PlatformType.FRAGILE) {
          // Draw cracks
          ctx.strokeStyle = 'rgba(0,0,0,0.2)';
          ctx.beginPath();
          ctx.moveTo(p.x + 20, p.y); ctx.lineTo(p.x + 30, p.y + 15); ctx.lineTo(p.x + 25, p.y + 30);
          ctx.stroke();
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player
    ctx.fillStyle = 'rgba(0,0,0,0.15)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4, player.pos.y + 4, player.width, player.height, 8);
    ctx.fill();

    // Squash and stretch
    let drawW = player.width;
    let drawH = player.height;
    if (!player.isGrounded && Math.abs(player.vel.y) > 2) {
        drawW *= 0.9;
        drawH *= 1.1;
    }

    ctx.fillStyle = COLORS.PLAYER;
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2, player.pos.y + (player.height - drawH), drawW, drawH, 8);
    ctx.fill();

    // Eyes
    const eyeOffsetX = player.vel.x > 0 ? 4 : (player.vel.x < 0 ? -4 : 0);
    ctx.fillStyle = '#fff';
    ctx.fillRect(player.pos.x + 8 + eyeOffsetX, player.pos.y + 10, 8, 8);
    ctx.fillRect(player.pos.x + 24 + eyeOffsetX, player.pos.y + 10, 8, 8);
    ctx.fillStyle = '#000';
    ctx.fillRect(player.pos.x + 11 + eyeOffsetX, player.pos.y + 13, 3, 3);
    ctx.fillRect(player.pos.x + 27 + eyeOffsetX, player.pos.y + 13, 3, 3);

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
    ctx.beginPath();
    ctx.arc(x, y, 30 * scale, 0, Math.PI * 2);
    ctx.arc(x + 40 * scale, y, 50 * scale, 0, Math.PI * 2);
    ctx.arc(x + 90 * scale, y, 35 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + (rb | 0)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full cursor-none" />;
};

export default GameCanvas;

export interface Vector2D {
  x: number;
  y: number;
}

export enum PlatformType {
  NORMAL = 'NORMAL',
  BOUNCY = 'BOUNCY',
  MOVING = 'MOVING',
  FRAGILE = 'FRAGILE',
  BOOSTER = 'BOOSTER',
  ICE = 'ICE',
  SLOW = 'SLOW',
  FINISH = 'FINISH'
}

export interface Platform {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  type: PlatformType;
  color: string;
  moveRange?: number;
  moveSpeed?: number;
  initialX?: number;
  decay?: number; // For FRAGILE platforms
  isTouched?: boolean;
}

export interface Player {
  pos: Vector2D;
  vel: Vector2D;
  width: number;
  height: number;
  isGrounded: boolean;
  jumpCount: number;
  isWallSliding: boolean;
  lastWallJumpDir: number;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export interface GameState {
  player: Player;
  platforms: Platform[];
  particles: Particle[];
  cameraX: number;
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  distanceReached: number;
  highSpeedMode: boolean;
}

export interface Encouragement {
  text: string;
  mood: 'happy' | 'motivational' | 'funny';
}

export const GRAVITY = 0.5;
export const JUMP_FORCE = -12;
export const WALL_JUMP_FORCE_X = 9;
export const WALL_JUMP_FORCE_Y = -11;
export const MOVE_SPEED = 0.8;
export const MAX_SPEED = 9;
export const FRICTION = 0.85;
export const ICE_FRICTION = 0.98;
export const SLOW_FRICTION = 0.6;
export const WORLD_WIDTH = 10000000; 
export const WORLD_HEIGHT = 800;

export const TARGET_SCORE = 1000000;

export const COLORS = {
  SKY: '#bae6fd', 
  CLOUD: '#ffffff',
  GRASS: '#4ade80',
  BOUNCY: '#f472b6',
  MOVING: '#60a5fa',
  FRAGILE: '#fb923c', 
  BOOSTER: '#a855f7',
  ICE: '#99f6e4', // Teal-200
  SLOW: '#94a3b8', // Slate-400
  PLAYER: '#fbbf24',
  FINISH: '#ef4444', 
};

import React from 'react';
import { TARGET_SCORE } from '../constants';

interface UIOverlayProps {
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  encouragement: string;
  onRestart: () => void;
}

const UIOverlay: React.FC<UIOverlayProps> = ({ score, isGameOver, isGameWon, encouragement, onRestart }) => {
  const progress = Math.min(100, (score / TARGET_SCORE) * 100);

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-6 font-['Quicksand']">
      {/* Top Bar */}
      <div className="flex justify-between items-start">
        <div className="flex flex-col gap-2">
          <div className="bg-white/90 backdrop-blur-sm px-6 py-3 rounded-2xl shadow-lg border-b-4 border-sky-300">
            <h1 className="text-xl font-bold text-sky-600 font-['Fredoka_One'] tracking-wide">SKY-HIGH HOPS</h1>
            <p className="text-gray-700 font-bold text-2xl tabular-nums">
              {score.toLocaleString()} <span className="text-sm font-normal text-gray-400">PTS</span>
            </p>
          </div>

          {/* Progress Bar */}
          <div className="w-64 h-4 bg-white/50 rounded-full border border-white overflow-hidden backdrop-blur-sm">
            <div 
              className="h-full bg-gradient-to-r from-sky-400 to-purple-400 transition-all duration-500 ease-out"
              style={{ width: `${progress}%` }}
            />
          </div>
          <p className="text-xs font-bold text-sky-600 drop-shadow-sm">ROAD TO 1,000,000</p>
        </div>

        <div className="bg-white/90 backdrop-blur-sm p-4 rounded-xl shadow-md border-r-4 border-amber-300 max-w-xs transition-all duration-300">
          <p className="text-amber-600 font-bold italic text-xs uppercase tracking-tighter mb-1">Spirit Guide</p>
          <p className="text-gray-700 font-medium text-sm leading-tight italic">"{encouragement}"</p>
        </div>
      </div>

      {/* Controls Help */}
      {!isGameOver && !isGameWon && (
        <div className="flex justify-center mb-4">
          <div className="bg-white/30 backdrop-blur-md text-sky-900 px-6 py-2 rounded-full text-xs font-bold shadow-sm flex gap-4 border border-white/50">
            <span>[W] FORWARD</span>
            <span className="opacity-40">|</span>
            <span>[S] BACKWARD</span>
            <span className="opacity-40">|</span>
            <span>[SPACE] JUMP</span>
          </div>
        </div>
      )}

      {/* Game States */}
      {(isGameOver || isGameWon) && (
        <div className="absolute inset-0 bg-sky-900/40 backdrop-blur-md flex items-center justify-center pointer-events-auto z-50">
          <div className="bg-white p-12 rounded-[3rem] shadow-2xl border-b-8 border-sky-200 text-center transform transition-all animate-in zoom-in duration-300 max-w-lg">
            {isGameWon ? (
              <>
                <h2 className="text-7xl font-['Fredoka_One'] text-purple-500 mb-4 animate-bounce">LEGEND! 🌈</h2>
                <p className="text-xl text-gray-600 mb-8 font-semibold">You reached 1,000,000 points!</p>
              </>
            ) : (
              <>
                <h2 className="text-7xl font-['Fredoka_One'] text-orange-400 mb-4">OOPS! ☁️</h2>
                <p className="text-xl text-gray-600 mb-2 font-semibold">The clouds were too slippery...</p>
                <p className="text-4xl font-bold text-sky-500 mb-8">{score.toLocaleString()} <span className="text-sm">PTS</span></p>
              </>
            )}
            <button 
              onClick={onRestart}
              className="group relative bg-sky-400 hover:bg-sky-500 text-white font-bold py-5 px-12 rounded-2xl text-2xl shadow-xl transition-all active:scale-95 overflow-hidden"
            >
              <span className="relative z-10">PLAY AGAIN</span>
              <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default UIOverlay;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, WALL_JUMP_FORCE_X, WALL_JUMP_FORCE_Y, MOVE_SPEED, MAX_SPEED, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT, TARGET_SCORE } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
  });

  const [encouragement, setEncouragement] = useState("One million points awaits! Start hopping!");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentScore: number) => {
    const newPlatforms: Platform[] = [];

    // Difficulty scaling
    const difficultyProgress = Math.min(1, currentScore / TARGET_SCORE);
    const MAX_VERTICAL_UP = 110 + (difficultyProgress * 30);
    const MAX_VERTICAL_DOWN = 180 + (difficultyProgress * 40);
    const baseWidth = 140 - (difficultyProgress * 60); // Platforms get smaller

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 400, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 400;
    } else {
        // Find last platform to bridge from
        lastX = startX;
        lastY = 400; // Generic fallback
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = baseWidth + Math.random() * 80;
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);
      nextY = Math.max(150, Math.min(580, nextY));

      const yDiff = lastY - nextY;
      let maxGap = 240 + (difficultyProgress * 80); 
      if (yDiff > 50) maxGap = 160 + (difficultyProgress * 40); 

      const gap = 80 + Math.random() * (maxGap - 80);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      // Platform selection
      if (typeSeed > 0.94) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.88) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 60 + Math.random() * 120;
        moveSpeed = 1.0 + Math.random() * 2.0;
        nextX += moveRange / 2;
      } else if (typeSeed > 0.82) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = Math.max(20, 50 - (difficultyProgress * 30)); 
      } else if (typeSeed > 0.76) {
        type = PlatformType.BOOSTER;
        color = COLORS.BOOSTER;
      } else if (typeSeed > 0.70) {
        type = PlatformType.ICE;
        color = COLORS.ICE;
      } else if (typeSeed > 0.64) {
        type = PlatformType.SLOW;
        color = COLORS.SLOW;
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const resetGame = useCallback(() => {
    keys.current = {};
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const initialPlatforms = generatePlatforms(0, 40, 0);

    setGameState({
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
    });
    setEncouragement("1,000,000 points is the goal. Stay focused!");
  }, [generatePlatforms]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 15000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon) return prev;

      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;

      // Infinite level generation trigger
      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 25, prev.score);
        newPlatformsList = [...newPlatformsList, ...appended];
        // Cleanup old platforms
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1000);
      }

      // Physics variables
      let currentFriction = FRICTION;
      let currentMoveSpeed = MOVE_SPEED;

      // Collision loop prep
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        // Moving platform
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        // Fragile decay
        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        // Ground check
        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = JUMP_FORCE * 1.65;
            for (let i = 0; i < 5; i++) {
              newParticles.push({
                x: newPlayer.pos.x + newPlayer.width / 2, y: newPlayer.pos.y + newPlayer.height,
                vx: (Math.random() - 0.5) * 8, vy: -Math.random() * 5,
                life: 1.0, color: COLORS.BOUNCY, size: 4
              });
            }
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 26; 
             newPlayer.vel.y = -4;
             for (let i = 0; i < 12; i++) {
                newParticles.push({
                  x: newPlayer.pos.x, y: newPlayer.pos.y + 20,
                  vx: -Math.random() * 12, vy: (Math.random() - 0.5) * 6,
                  life: 1.0, color: COLORS.BOOSTER, size: 5
                });
             }
          } else if (currentP.type === PlatformType.ICE) {
            currentFriction = ICE_FRICTION;
          } else if (currentP.type === PlatformType.SLOW) {
            currentFriction = SLOW_FRICTION;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        // Wall check
        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 12) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 12) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      // Input handling
      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * currentMoveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      // Speed capping
      const maxS = MAX_SPEED * (newPlayer.vel.x > 15 ? 3 : 1.2);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      // Gravity and Wall sliding
      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 2.5);
      } else {
        newPlayer.vel.y += GRAVITY;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      // Jump Logic
      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = JUMP_FORCE;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = WALL_JUMP_FORCE_Y;
          newPlayer.vel.x = -wallDirection * WALL_JUMP_FORCE_X;
          keys.current['Space'] = false;
          for (let i = 0; i < 6; i++) {
            newParticles.push({
              x: newPlayer.pos.x + (wallDirection === 1 ? newPlayer.width : 0),
              y: newPlayer.pos.y + 20,
              vx: wallDirection * 4, vy: -3,
              life: 1.0, color: COLORS.CLOUD, size: 4
            });
          }
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - 300) - prev.cameraX) * 0.08;
      const score = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > WORLD_HEIGHT + 300) {
        isGameOver = true;
        pendingEncouragementContext.current = `Tumbled at ${score} points!`;
      }

      if (score >= TARGET_SCORE) {
        isGameWon = true;
        pendingEncouragementContext.current = "1,000,000 REACHED! YOU ARE A LEGEND!";
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        score,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        encouragement={encouragement}
        onRestart={resetGame}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS, TARGET_SCORE } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, score, highSpeedMode } = gameState;

    // 1. Draw Background (Altitude & Space transition)
    const skyTransition = Math.min(1, score / TARGET_SCORE);
    const topColor = lerpColor('#7dd3fc', '#020617', skyTransition);
    const bottomColor = lerpColor('#e0f2fe', '#1e293b', skyTransition);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax Clouds/Stars
    ctx.save();
    ctx.translate(-cameraX * 0.3, 0);
    const cloudCount = 15;
    for (let i = 0; i < cloudCount; i++) {
        const xPos = (Math.floor(cameraX * 0.3 / 800) * 800) + (i * 800);
        if (skyTransition < 0.8) {
            drawCloud(ctx, xPos + 200, 150 + (i % 4) * 60, 0.7 + (i % 3) * 0.4);
        } else {
            // Stars in space
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(xPos + (i * 123) % 800, 100 + (i * 321) % 500, 2, 0, Math.PI * 2);
            ctx.fill();
        }
    }
    ctx.restore();

    // Speed Lines for High Speed
    if (highSpeedMode) {
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
      ctx.lineWidth = 2;
      for(let i=0; i<20; i++) {
        const x = (Date.now() + i * 100) % canvas.width;
        const y = (i * 47) % canvas.height;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + 100, y);
        ctx.stroke();
      }
    }

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, 0);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Platform shadow
      ctx.fillStyle = 'rgba(0,0,0,0.15)';
      ctx.beginPath();
      ctx.roundRect(p.x + 5, p.y + 6, p.width, p.height, 12);
      ctx.fill();

      // Platform body
      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 30);
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 12);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Type details
      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (p.type === PlatformType.ICE) {
        ctx.strokeStyle = '#ccfbf1';
        ctx.lineWidth = 4;
        ctx.stroke();
        // Shine lines
        ctx.strokeStyle = 'rgba(255,255,255,0.6)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(p.x + 10, p.y + 8); ctx.lineTo(p.x + p.width - 10, p.y + 8);
        ctx.stroke();
      } else if (p.type === PlatformType.SLOW) {
        ctx.fillStyle = 'rgba(0,0,0,0.1)';
        ctx.fillRect(p.x + 10, p.y + p.height - 10, p.width - 20, 5);
      } else if (p.type === PlatformType.BOOSTER) {
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        for(let i=0; i<4; i++) {
          const arrowX = p.x + 25 + i * (p.width/4);
          ctx.beginPath();
          ctx.moveTo(arrowX, p.y + 10); ctx.lineTo(arrowX + 15, p.y + 17); ctx.lineTo(arrowX, p.y + 25);
          ctx.fill();
        }
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player Rendering
    const drawW = player.isWallSliding ? player.width * 0.8 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.2 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 5 : -5) : 0;

    // Player Shadow
    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4 + xOffset, player.pos.y + 5, drawW, drawH, 10);
    ctx.fill();

    // Player Body
    ctx.fillStyle = COLORS.PLAYER;
    if (highSpeedMode) ctx.fillStyle = '#fef3c7'; // Glow when fast
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 10);
    ctx.fill();

    // Eyes and Face
    const eyeDir = player.vel.x > 0 ? 5 : (player.vel.x < 0 ? -5 : 0);
    ctx.fillStyle = '#fff';
    ctx.fillRect(player.pos.x + 8 + eyeDir, player.pos.y + 12, 8, 8);
    ctx.fillRect(player.pos.x + 24 + eyeDir, player.pos.y + 12, 8, 8);
    ctx.fillStyle = '#000';
    ctx.fillRect(player.pos.x + 11 + eyeDir, player.pos.y + 15, 3, 3);
    ctx.fillRect(player.pos.x + 27 + eyeDir, player.pos.y + 15, 3, 3);

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
    ctx.beginPath();
    ctx.arc(x, y, 35 * scale, 0, Math.PI * 2);
    ctx.arc(x + 45 * scale, y - 10 * scale, 55 * scale, 0, Math.PI * 2);
    ctx.arc(x + 95 * scale, y, 40 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + (rb | 0)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full cursor-none" />;
};

export default GameCanvas;

export const GRAVITY = 0.52; // Slightly higher gravity for tighter jumps
export const JUMP_FORCE = -12.5; 
export const WALL_JUMP_FORCE_X = 9.5;
export const WALL_JUMP_FORCE_Y = -11.5;
export const MOVE_SPEED = 0.85;
export const MAX_SPEED = 9.5;
export const FRICTION = 0.86;
export const ICE_FRICTION = 0.985;
export const SLOW_FRICTION = 0.55;
export const WORLD_WIDTH = 10000000; 
export const WORLD_HEIGHT = 800;

export const TARGET_METERS = 1000000; // Goal is 1 million meters

export const COLORS = {
  SKY: '#bae6fd', 
  CLOUD: '#ffffff',
  GRASS: '#4ade80',
  BOUNCY: '#f472b6',
  MOVING: '#60a5fa',
  FRAGILE: '#fb923c', 
  BOOSTER: '#a855f7',
  ICE: '#99f6e4', 
  SLOW: '#94a3b8', 
  PLAYER: '#fbbf24',
  FINISH: '#ef4444', 
};

import React from 'react';
import { TARGET_METERS } from '../constants';

interface UIOverlayProps {
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  encouragement: string;
  onRestart: () => void;
}

const UIOverlay: React.FC<UIOverlayProps> = ({ score, isGameOver, isGameWon, encouragement, onRestart }) => {
  const progress = Math.min(100, (score / TARGET_METERS) * 100);

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-6 font-['Quicksand']">
      {/* Top Bar */}
      <div className="flex justify-between items-start">
        <div className="flex flex-col gap-2">
          <div className="bg-white/90 backdrop-blur-sm px-6 py-3 rounded-2xl shadow-lg border-b-4 border-sky-300">
