  );
};

export default UIOverlay;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, WALL_JUMP_FORCE_X, WALL_JUMP_FORCE_Y, MOVE_SPEED, MAX_SPEED, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT, TARGET_METERS } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
  });

  const [encouragement, setEncouragement] = useState("One million meters is a long way. Better get moving!");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number) => {
    const newPlatforms: Platform[] = [];

    // Aggressive difficulty scaling
    // Logarithmic-like scaling to make the first 10k manageable but then it spikes.
    const difficultyProgress = Math.min(1, Math.pow(currentMeters / (TARGET_METERS * 0.1), 0.7)); 
    const extremeProgress = Math.min(1, currentMeters / TARGET_METERS);

    const MAX_VERTICAL_UP = 110 + (difficultyProgress * 50); // Harder climbs
    const MAX_VERTICAL_DOWN = 180 + (difficultyProgress * 60);
    const baseWidth = 150 - (difficultyProgress * 100); // Platforms shrink to tiny slivers

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 300, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 300;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = Math.max(30, baseWidth + Math.random() * 50);
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);

      // World is taller at high altitudes
      nextY = Math.max(100, Math.min(650, nextY));

      const yDiff = lastY - nextY;
      // Gaps push the absolute limits of the jump physics (Max horizontal ~340)
      let maxGap = 240 + (difficultyProgress * 120); 
      if (yDiff > 60) maxGap = 160 + (difficultyProgress * 90); 

      const gap = 90 + Math.random() * (maxGap - 90);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      // Type probabilities shift towards harder types
      const pBouncy = 0.92 - (extremeProgress * 0.1);
      const pMoving = 0.82 - (extremeProgress * 0.2);
      const pFragile = 0.70 - (extremeProgress * 0.3);
      const pBooster = 0.62 - (extremeProgress * 0.2);
      const pIce = 0.52 - (extremeProgress * 0.2);
      const pSlow = 0.42 - (extremeProgress * 0.2);

      if (typeSeed > pBouncy) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > pMoving) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 60 + Math.random() * (120 + difficultyProgress * 100);
        moveSpeed = 1.0 + Math.random() * (2.0 + extremeProgress * 2);
        nextX += moveRange / 2;
      } else if (typeSeed > pFragile) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = Math.max(12, 45 - (difficultyProgress * 35)); // Almost instant collapse late game
      } else if (typeSeed > pBooster) {
        type = PlatformType.BOOSTER;
        color = COLORS.BOOSTER;
      } else if (typeSeed > pIce) {
        type = PlatformType.ICE;
        color = COLORS.ICE;
      } else if (typeSeed > pSlow) {
        type = PlatformType.SLOW;
        color = COLORS.SLOW;
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const resetGame = useCallback(() => {
    keys.current = {};
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const initialPlatforms = generatePlatforms(0, 45, 0);

    setGameState({
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
    });
    setEncouragement("Target: 1,000,000 Meters. No mistakes allowed!");
  }, [generatePlatforms]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 18000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon) return prev;

      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;

      // Fetch next platform set
      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 30, prev.score);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1200);
      }

      let currentFriction = FRICTION;
      let currentMoveSpeed = MOVE_SPEED;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = JUMP_FORCE * 1.62;
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 28; 
             newPlayer.vel.y = -5;
          } else if (currentP.type === PlatformType.ICE) {
            currentFriction = ICE_FRICTION;
          } else if (currentP.type === PlatformType.SLOW) {
            currentFriction = SLOW_FRICTION;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 12) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 12) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * currentMoveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = MAX_SPEED * (newPlayer.vel.x > 18 ? 3.5 : 1.25);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 2.5);
      } else {
        newPlayer.vel.y += GRAVITY;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = JUMP_FORCE;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = WALL_JUMP_FORCE_Y;
          newPlayer.vel.x = -wallDirection * WALL_JUMP_FORCE_X;
          keys.current['Space'] = false;
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - 350) - prev.cameraX) * 0.08;
      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > WORLD_HEIGHT + 400) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell after ${meters} meters. Hard luck!`;
      }

      if (meters >= TARGET_METERS) {
        isGameWon = true;
        pendingEncouragementContext.current = "1,000,000 METERS! You are truly the king of the clouds!";
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        encouragement={encouragement}
        onRestart={resetGame}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
// Fixed: Changed non-existent TARGET_SCORE to TARGET_METERS
import { COLORS, TARGET_METERS } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, score, highSpeedMode } = gameState;

    // 1. Draw Background (Altitude & Space transition)
    // Fixed: Used TARGET_METERS for calculating sky transition progress
    const skyTransition = Math.min(1, score / TARGET_METERS);
    const topColor = lerpColor('#7dd3fc', '#020617', skyTransition);
    const bottomColor = lerpColor('#e0f2fe', '#1e293b', skyTransition);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax Clouds/Stars
    ctx.save();
    ctx.translate(-cameraX * 0.3, 0);
    const cloudCount = 15;
    for (let i = 0; i < cloudCount; i++) {
        const xPos = (Math.floor(cameraX * 0.3 / 800) * 800) + (i * 800);
        if (skyTransition < 0.8) {
            drawCloud(ctx, xPos + 200, 150 + (i % 4) * 60, 0.7 + (i % 3) * 0.4);
        } else {
            // Stars in space
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(xPos + (i * 123) % 800, 100 + (i * 321) % 500, 2, 0, Math.PI * 2);
            ctx.fill();
        }
    }
    ctx.restore();

    // Speed Lines for High Speed
    if (highSpeedMode) {
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
      ctx.lineWidth = 2;
      for(let i=0; i<20; i++) {
        const x = (Date.now() + i * 100) % canvas.width;
        const y = (i * 47) % canvas.height;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + 100, y);
        ctx.stroke();
      }
    }

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, 0);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Platform shadow
      ctx.fillStyle = 'rgba(0,0,0,0.15)';
      ctx.beginPath();
      ctx.roundRect(p.x + 5, p.y + 6, p.width, p.height, 12);
      ctx.fill();

      // Platform body
      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 30);
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 12);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Type details
      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (p.type === PlatformType.ICE) {
        ctx.strokeStyle = '#ccfbf1';
        ctx.lineWidth = 4;
        ctx.stroke();
        // Shine lines
        ctx.strokeStyle = 'rgba(255,255,255,0.6)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(p.x + 10, p.y + 8); ctx.lineTo(p.x + p.width - 10, p.y + 8);
        ctx.stroke();
      } else if (p.type === PlatformType.SLOW) {
        ctx.fillStyle = 'rgba(0,0,0,0.1)';
        ctx.fillRect(p.x + 10, p.y + p.height - 10, p.width - 20, 5);
      } else if (p.type === PlatformType.BOOSTER) {
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        for(let i=0; i<4; i++) {
          const arrowX = p.x + 25 + i * (p.width/4);
          ctx.beginPath();
          ctx.moveTo(arrowX, p.y + 10); ctx.lineTo(arrowX + 15, p.y + 17); ctx.lineTo(arrowX, p.y + 25);
          ctx.fill();
        }
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player Rendering
    const drawW = player.isWallSliding ? player.width * 0.8 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.2 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 5 : -5) : 0;

    // Player Shadow
    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4 + xOffset, player.pos.y + 5, drawW, drawH, 10);
    ctx.fill();

    // Player Body
    ctx.fillStyle = COLORS.PLAYER;
    if (highSpeedMode) ctx.fillStyle = '#fef3c7'; // Glow when fast
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 10);
    ctx.fill();

    // Eyes and Face
    const eyeDir = player.vel.x > 0 ? 5 : (player.vel.x < 0 ? -5 : 0);
    ctx.fillStyle = '#fff';
    ctx.fillRect(player.pos.x + 8 + eyeDir, player.pos.y + 12, 8, 8);
    ctx.fillRect(player.pos.x + 24 + eyeDir, player.pos.y + 12, 8, 8);
    ctx.fillStyle = '#000';
    ctx.fillRect(player.pos.x + 11 + eyeDir, player.pos.y + 15, 3, 3);
    ctx.fillRect(player.pos.x + 27 + eyeDir, player.pos.y + 15, 3, 3);

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
    ctx.beginPath();
    ctx.arc(x, y, 35 * scale, 0, Math.PI * 2);
    ctx.arc(x + 45 * scale, y - 10 * scale, 55 * scale, 0, Math.PI * 2);
    ctx.arc(x + 95 * scale, y, 40 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + (rb | 0)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full cursor-none" />;
};

export default GameCanvas;

export const GRAVITY = 0.58; // Increased gravity for heavier feel
export const JUMP_FORCE = -12.8; 
export const WALL_JUMP_FORCE_X = 10;
export const WALL_JUMP_FORCE_Y = -12;
export const MOVE_SPEED = 0.75; // Slower acceleration
export const MAX_SPEED = 8.5;  // Lower top speed
export const FRICTION = 0.84;
export const ICE_FRICTION = 0.99;
export const SLOW_FRICTION = 0.5;
export const WORLD_WIDTH = 10000000; 
export const WORLD_HEIGHT = 800;

export const TARGET_METERS = 1000000; 

export const COLORS = {
  SKY: '#bae6fd', 
  CLOUD: '#ffffff',
  GRASS: '#4ade80',
  BOUNCY: '#f472b6',
  MOVING: '#60a5fa',
  FRAGILE: '#fb923c', 
  BOOSTER: '#a855f7',
  ICE: '#99f6e4', 
  SLOW: '#94a3b8', 
  PLAYER: '#fbbf24',
  FINISH: '#ef4444', 
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, WALL_JUMP_FORCE_X, WALL_JUMP_FORCE_Y, MOVE_SPEED, MAX_SPEED, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT, TARGET_METERS } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
  });

  const [encouragement, setEncouragement] = useState("One million meters? In this gravity? Good luck.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number) => {
    const newPlatforms: Platform[] = [];

    // Very aggressive difficulty scaling - starts getting hard almost immediately
    const difficultyProgress = Math.min(1, Math.pow(currentMeters / (TARGET_METERS * 0.05), 0.5)); 
    const extremeProgress = Math.min(1, currentMeters / (TARGET_METERS * 0.5));

    const MAX_VERTICAL_UP = 100 + (difficultyProgress * 60); 
    const MAX_VERTICAL_DOWN = 160 + (difficultyProgress * 80);
    const baseWidth = 110 - (difficultyProgress * 85); // Platforms shrink to tiny 25px wide blocks

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 250, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 250;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = Math.max(25, baseWidth + Math.random() * 40);
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);

      nextY = Math.max(80, Math.min(680, nextY));

      const yDiff = lastY - nextY;
      // Gaps are pushed to the absolute edge of possibility
      let maxGap = 220 + (difficultyProgress * 130); // ~350 max
      if (yDiff > 40) maxGap = 150 + (difficultyProgress * 90); 

      const gap = 100 + Math.random() * (maxGap - 100);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      // Type probabilities shift towards harder types much earlier
      const pBouncy = 0.90 - (extremeProgress * 0.2);
      const pMoving = 0.80 - (extremeProgress * 0.3);
      const pFragile = 0.65 - (extremeProgress * 0.4);
      const pBooster = 0.58 - (extremeProgress * 0.2);
      const pIce = 0.45 - (extremeProgress * 0.2);
      const pSlow = 0.35 - (extremeProgress * 0.2);

      if (typeSeed > pBouncy) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > pMoving) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * (100 + difficultyProgress * 150);
        moveSpeed = 1.2 + Math.random() * (2.5 + extremeProgress * 3);
        nextX += moveRange / 2;
      } else if (typeSeed > pFragile) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = Math.max(10, 40 - (difficultyProgress * 32)); 
      } else if (typeSeed > pBooster) {
        type = PlatformType.BOOSTER;
        color = COLORS.BOOSTER;
      } else if (typeSeed > pIce) {
        type = PlatformType.ICE;
        color = COLORS.ICE;
      } else if (typeSeed > pSlow) {
        type = PlatformType.SLOW;
        color = COLORS.SLOW;
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const resetGame = useCallback(() => {
    keys.current = {};
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const initialPlatforms = generatePlatforms(0, 50, 0);

    setGameState({
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
    });
    setEncouragement("1M Meters. High Gravity. Tiny Platforms. Go.");
  }, [generatePlatforms]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 15000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon) return prev;

      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 30, prev.score);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1500);
      }

      let currentFriction = FRICTION;
      let currentMoveSpeed = MOVE_SPEED;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = JUMP_FORCE * 1.6;
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 30; 
             newPlayer.vel.y = -6;
          } else if (currentP.type === PlatformType.ICE) {
            currentFriction = ICE_FRICTION;
          } else if (currentP.type === PlatformType.SLOW) {
            currentFriction = SLOW_FRICTION;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 12) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 12) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * currentMoveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = MAX_SPEED * (newPlayer.vel.x > 20 ? 3.5 : 1.3);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3);
      } else {
        newPlayer.vel.y += GRAVITY;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = JUMP_FORCE;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = WALL_JUMP_FORCE_Y;
          newPlayer.vel.x = -wallDirection * WALL_JUMP_FORCE_X;
          keys.current['Space'] = false;
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - 300) - prev.cameraX) * 0.1;
      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > WORLD_HEIGHT + 450) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell after ${meters}m. Traversal is tough.`;
      }

      if (meters >= TARGET_METERS) {
        isGameWon = true;
        pendingEncouragementContext.current = "THE IMPOSSIBLE IS DONE! 1M METERS!";
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 20
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        encouragement={encouragement}
        onRestart={resetGame}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS, TARGET_METERS } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, score, highSpeedMode } = gameState;

    // 1. Draw Background
    const skyTransition = Math.min(1, score / TARGET_METERS);
    const topColor = lerpColor('#7dd3fc', '#020617', skyTransition);
    const bottomColor = lerpColor('#e0f2fe', '#1e293b', skyTransition);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax Clouds/Stars
    ctx.save();
    ctx.translate(-cameraX * 0.3, 0);
    const cloudCount = 15;
    for (let i = 0; i < cloudCount; i++) {
        const xPos = (Math.floor(cameraX * 0.3 / 800) * 800) + (i * 800);
        if (skyTransition < 0.8) {
            drawCloud(ctx, xPos + 200, 150 + (i % 4) * 60, 0.7 + (i % 3) * 0.4);
        } else {
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(xPos + (i * 123) % 800, 100 + (i * 321) % 500, 2, 0, Math.PI * 2);
            ctx.fill();
        }
    }
    ctx.restore();

    // Speed Lines
    if (highSpeedMode) {
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
      ctx.lineWidth = 2;
      for(let i=0; i<20; i++) {
        const x = (Date.now() + i * 100) % canvas.width;
        const y = (i * 47) % canvas.height;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + 100, y);
        ctx.stroke();
      }
    }

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, 0);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      ctx.fillStyle = 'rgba(0,0,0,0.15)';
      ctx.beginPath();
      ctx.roundRect(p.x + 5, p.y + 6, p.width, p.height, 12);
      ctx.fill();

      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 30);
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 12);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (p.type === PlatformType.ICE) {
        ctx.strokeStyle = '#ccfbf1';
        ctx.lineWidth = 4;
        ctx.stroke();
      } else if (p.type === PlatformType.BOOSTER) {
        ctx.fillStyle = 'rgba(255,255,255,0.5)';
        for(let i=0; i<3; i++) {
          const arrowX = p.x + 10 + i * (p.width/3);
          ctx.beginPath();
          ctx.moveTo(arrowX, p.y + 10); ctx.lineTo(arrowX + 10, p.y + 17); ctx.lineTo(arrowX, p.y + 25);
          ctx.fill();
        }
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player Rendering
    const drawW = player.isWallSliding ? player.width * 0.8 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.2 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 5 : -5) : 0;

    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4 + xOffset, player.pos.y + 5, drawW, drawH, 10);
    ctx.fill();

    ctx.fillStyle = COLORS.PLAYER;
    if (highSpeedMode) ctx.fillStyle = '#fef3c7'; 
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 10);
    ctx.fill();

    // Eyes
    const eyeDir = player.vel.x > 0 ? 5 : (player.vel.x < 0 ? -5 : 0);
    ctx.fillStyle = '#fff';
    ctx.fillRect(player.pos.x + 8 + eyeDir, player.pos.y + 12, 8, 8);
    ctx.fillRect(player.pos.x + 24 + eyeDir, player.pos.y + 12, 8, 8);
    ctx.fillStyle = '#000';
    ctx.fillRect(player.pos.x + 11 + eyeDir, player.pos.y + 15, 3, 3);
    ctx.fillRect(player.pos.x + 27 + eyeDir, player.pos.y + 15, 3, 3);

    // NEW: Mouth
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 2;
    ctx.beginPath();
    const mouthY = player.pos.y + 28;
    const mouthX = player.pos.x + 20 + eyeDir;

    if (Math.abs(player.vel.y) > 2) {
        // "O" shape when jumping/falling
        ctx.arc(mouthX, mouthY, 4, 0, Math.PI * 2);
    } else if (player.vel.x !== 0) {
        // Determination line
        ctx.moveTo(mouthX - 5, mouthY);
        ctx.lineTo(mouthX + 5, mouthY);
    } else {
        // Simple smile when idle
        ctx.arc(mouthX, mouthY - 3, 5, 0.2 * Math.PI, 0.8 * Math.PI);
    }
    ctx.stroke();

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
    ctx.beginPath();
    ctx.arc(x, y, 35 * scale, 0, Math.PI * 2);
    ctx.arc(x + 45 * scale, y - 10 * scale, 55 * scale, 0, Math.PI * 2);
    ctx.arc(x + 95 * scale, y, 40 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + (rb | 0)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full cursor-none" />;
};

export default GameCanvas;

export const GRAVITY = 0.65; // Much heavier gravity
export const JUMP_FORCE = -13.2; 
export const WALL_JUMP_FORCE_X = 10.5;
export const WALL_JUMP_FORCE_Y = -12.5;
export const MOVE_SPEED = 0.65; // Even slower acceleration for harder starts
export const MAX_SPEED = 8.0;  // Lower capped top speed
export const FRICTION = 0.82;
export const ICE_FRICTION = 0.992;
export const SLOW_FRICTION = 0.45;
export const WORLD_WIDTH = 10000000; 
export const WORLD_HEIGHT = 1200; // Increased logical world height

export const TARGET_METERS = 1000000; 

export const COLORS = {
  SKY: '#bae6fd', 
  CLOUD: '#ffffff',
  GRASS: '#4ade80',
  BOUNCY: '#f472b6',
  MOVING: '#60a5fa',
  FRAGILE: '#fb923c', 
  BOOSTER: '#a855f7',
  ICE: '#99f6e4', 
  SLOW: '#94a3b8', 
  PLAYER: '#fbbf24',
  FINISH: '#ef4444', 
};

export interface Vector2D {
  x: number;
  y: number;
}

export enum PlatformType {
  NORMAL = 'NORMAL',
  BOUNCY = 'BOUNCY',
  MOVING = 'MOVING',
  FRAGILE = 'FRAGILE',
  BOOSTER = 'BOOSTER',
  ICE = 'ICE',
  SLOW = 'SLOW',
  FINISH = 'FINISH'
}

export interface Platform {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  type: PlatformType;
  color: string;
  moveRange?: number;
  moveSpeed?: number;
  initialX?: number;
  decay?: number; 
  isTouched?: boolean;
}

export interface Player {
  pos: Vector2D;
  vel: Vector2D;
  width: number;
  height: number;
  isGrounded: boolean;
  jumpCount: number;
  isWallSliding: boolean;
  lastWallJumpDir: number;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export interface GameState {
  player: Player;
  platforms: Platform[];
  particles: Particle[];
  cameraX: number;
  cameraY: number; // Added cameraY for vertical tracking
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  distanceReached: number;
  highSpeedMode: boolean;
}

export interface Encouragement {
  text: string;
  mood: 'happy' | 'motivational' | 'funny';
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Particle } from './types';
import { GRAVITY, JUMP_FORCE, WALL_JUMP_FORCE_X, WALL_JUMP_FORCE_Y, MOVE_SPEED, MAX_SPEED, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT, TARGET_METERS } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    cameraY: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
  });

  const [encouragement, setEncouragement] = useState("One million meters? In this gravity? Good luck.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number) => {
    const newPlatforms: Platform[] = [];

    // Extreme difficulty scaling
    const difficultyProgress = Math.min(1, Math.pow(currentMeters / (TARGET_METERS * 0.05), 0.5)); 
    const extremeProgress = Math.min(1, currentMeters / (TARGET_METERS * 0.3));

    const MAX_VERTICAL_UP = 90 + (difficultyProgress * 70); 
    const MAX_VERTICAL_DOWN = 140 + (difficultyProgress * 90);
    const baseWidth = 100 - (difficultyProgress * 85); 

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 200, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 200;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = Math.max(15, baseWidth + Math.random() * 30); // Platforms can be as narrow as 15px
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);

      // Tighten vertical band to keep things manageable but hard
      nextY = Math.max(100, Math.min(900, nextY));

      const yDiff = lastY - nextY;
      // Precise gap calculation for punishing gameplay
      let maxGap = 210 + (difficultyProgress * 150); 
      if (yDiff > 30) maxGap = 140 + (difficultyProgress * 100); 

      const gap = 110 + Math.random() * (maxGap - 110);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      const pBouncy = 0.88 - (extremeProgress * 0.2);
      const pMoving = 0.78 - (extremeProgress * 0.3);
      const pFragile = 0.62 - (extremeProgress * 0.4);
      const pBooster = 0.55 - (extremeProgress * 0.2);

      if (typeSeed > pBouncy) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > pMoving) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 40 + Math.random() * (100 + difficultyProgress * 180);
        moveSpeed = 1.4 + Math.random() * (2.8 + extremeProgress * 3.5);
        nextX += moveRange / 2;
      } else if (typeSeed > pFragile) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = Math.max(8, 35 - (difficultyProgress * 30)); // Collapse extremely fast
      } else if (typeSeed > pBooster) {
        type = PlatformType.BOOSTER;
        color = COLORS.BOOSTER;
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const resetGame = useCallback(() => {
    keys.current = {};
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const initialPlatforms = generatePlatforms(0, 50, 0);

    setGameState({
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      cameraY: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
    });
    setEncouragement("Target: 1,000,000 Meters. No mistakes allowed.");
  }, [generatePlatforms]);

  useEffect(() => {
    resetGame();
  }, [resetGame]);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 18000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon) return prev;

      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 30, prev.score);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1500);
      }

      let currentFriction = FRICTION;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = JUMP_FORCE * 1.6;
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 28; 
             newPlayer.vel.y = -4;
          } else if (currentP.type === PlatformType.ICE) {
            currentFriction = ICE_FRICTION;
          } else if (currentP.type === PlatformType.SLOW) {
            currentFriction = SLOW_FRICTION;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 12) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 12) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * MOVE_SPEED;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = MAX_SPEED * (newPlayer.vel.x > 18 ? 3.5 : 1.25);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3.5);
      } else {
        newPlayer.vel.y += GRAVITY;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = JUMP_FORCE;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = WALL_JUMP_FORCE_Y;
          newPlayer.vel.x = -wallDirection * WALL_JUMP_FORCE_X;
          keys.current['Space'] = false;
        }
      }

      // Smooth camera tracking for both X and Y
      const cameraX = prev.cameraX + ((newPlayer.pos.x - 400) - prev.cameraX) * 0.1;
      const targetCameraY = newPlayer.pos.y - window.innerHeight / 2;
      const cameraY = prev.cameraY + (targetCameraY - prev.cameraY) * 0.08;

      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      // Punishing death: falling too far below current platforms band
      if (newPlayer.pos.y > prev.cameraY + window.innerHeight + 100) {
        isGameOver = true;
        pendingEncouragementContext.current = `Gravity won at ${meters}m. Tough luck.`;
      }

      if (meters >= TARGET_METERS) {
        isGameWon = true;
        pendingEncouragementContext.current = "LEGENDARY! YOU REACHED THE MILLION!";
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        cameraY,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        encouragement={encouragement}
        onRestart={resetGame}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS, TARGET_METERS } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, cameraY, score, highSpeedMode } = gameState;

    // 1. Draw Background
    const skyTransition = Math.min(1, score / TARGET_METERS);
    const topColor = lerpColor('#7dd3fc', '#020617', skyTransition);
    const bottomColor = lerpColor('#e0f2fe', '#1e293b', skyTransition);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax
    ctx.save();
    ctx.translate(-cameraX * 0.2, -cameraY * 0.1);
    const cloudCount = 20;
    for (let i = 0; i < cloudCount; i++) {
        const xPos = (Math.floor(cameraX * 0.2 / 800) * 800) + (i * 800);
        const yPos = (i * 200) % 1000;
        if (skyTransition < 0.85) {
            drawCloud(ctx, xPos + 100, yPos, 0.6 + (i % 3) * 0.4);
        } else {
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(xPos + (i * 157) % 800, yPos, 1.5, 0, Math.PI * 2);
            ctx.fill();
        }
    }
    ctx.restore();

    // Speed Lines
    if (highSpeedMode) {
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
      ctx.lineWidth = 1;
      for(let i=0; i<30; i++) {
        const x = (Date.now() + i * 150) % canvas.width;
        const y = (i * 37) % canvas.height;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + 120, y);
        ctx.stroke();
      }
    }

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, -cameraY);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Platform shadow
      ctx.fillStyle = 'rgba(0,0,0,0.1)';
      ctx.beginPath();
      ctx.roundRect(p.x + 4, p.y + 6, p.width, p.height, 10);
      ctx.fill();

      // Platform body
      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 30);
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 10);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Accents
      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 4;
        ctx.stroke();
      } else if (p.type === PlatformType.ICE) {
        ctx.strokeStyle = '#ccfbf1';
        ctx.lineWidth = 5;
        ctx.stroke();
      } else if (p.type === PlatformType.BOOSTER) {
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        const arrowCount = Math.max(1, Math.floor(p.width / 20));
        for(let i=0; i<arrowCount; i++) {
          const arrowX = p.x + 5 + i * 20;
          ctx.beginPath();
          ctx.moveTo(arrowX, p.y + 10); ctx.lineTo(arrowX + 10, p.y + 17); ctx.lineTo(arrowX, p.y + 25);
          ctx.fill();
        }
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player Rendering
    const drawW = player.isWallSliding ? player.width * 0.85 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.15 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 3 : -3) : 0;

    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 3 + xOffset, player.pos.y + 4, drawW, drawH, 10);
    ctx.fill();

    ctx.fillStyle = COLORS.PLAYER;
    if (highSpeedMode) ctx.fillStyle = '#fef3c7'; 
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 10);
    ctx.fill();

    // Face details
    const eyeDir = player.vel.x > 0 ? 4 : (player.vel.x < 0 ? -4 : 0);
    const eyeBaseY = player.pos.y + 12;
    ctx.fillStyle = '#fff';
    ctx.fillRect(player.pos.x + 8 + eyeDir, eyeBaseY, 8, 8);
    ctx.fillRect(player.pos.x + 24 + eyeDir, eyeBaseY, 8, 8);
    ctx.fillStyle = '#000';
    ctx.fillRect(player.pos.x + 11 + eyeDir, eyeBaseY + 3, 3, 3);
    ctx.fillRect(player.pos.x + 27 + eyeDir, eyeBaseY + 3, 3, 3);

    // Mouth
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 2;
    ctx.beginPath();
    const mouthY = player.pos.y + 28;
    const mouthX = player.pos.x + 20 + eyeDir;

    if (Math.abs(player.vel.y) > 3) {
        ctx.arc(mouthX, mouthY, 4, 0, Math.PI * 2); // Worried 'O' when in air
    } else if (Math.abs(player.vel.x) > 2) {
        ctx.moveTo(mouthX - 5, mouthY);
        ctx.lineTo(mouthX + 5, mouthY); // Serious line when running
    } else {
        ctx.arc(mouthX, mouthY - 2, 5, 0.1 * Math.PI, 0.9 * Math.PI); // Smile when idle/slow
    }
    ctx.stroke();

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
    ctx.beginPath();
    ctx.arc(x, y, 30 * scale, 0, Math.PI * 2);
    ctx.arc(x + 40 * scale, y - 10 * scale, 50 * scale, 0, Math.PI * 2);
    ctx.arc(x + 80 * scale, y, 35 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + (rb | 0)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full cursor-none" />;
};

export default GameCanvas;

export interface Vector2D {
  x: number;
  y: number;
}

export enum PlatformType {
  NORMAL = 'NORMAL',
  BOUNCY = 'BOUNCY',
  MOVING = 'MOVING',
  FRAGILE = 'FRAGILE',
  BOOSTER = 'BOOSTER',
  ICE = 'ICE',
  SLOW = 'SLOW',
  FINISH = 'FINISH'
}

export enum Difficulty {
  EASY = 'EASY',
  MEDIUM = 'MEDIUM',
  HARD = 'HARD'
}

export interface Platform {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  type: PlatformType;
  color: string;
  moveRange?: number;
  moveSpeed?: number;
  initialX?: number;
  decay?: number; 
  isTouched?: boolean;
}

export interface Player {
  pos: Vector2D;
  vel: Vector2D;
  width: number;
  height: number;
  isGrounded: boolean;
  jumpCount: number;
  isWallSliding: boolean;
  lastWallJumpDir: number;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export interface GameState {
  player: Player;
  platforms: Platform[];
  particles: Particle[];
  cameraX: number;
  cameraY: number;
  score: number;
  isGameOver: boolean;
  isGameWon: boolean;
  distanceReached: number;
  highSpeedMode: boolean;
  difficulty: Difficulty;
  targetMeters: number;
  isSelectingMode: boolean;
}

export interface Encouragement {
  text: string;
  mood: 'happy' | 'motivational' | 'funny';
}

export const DIFFICULTY_CONFIG = {
  EASY: {
    target: 10000,
    gravity: 0.5,
    moveSpeed: 0.85,
    maxSpeed: 10,
    jumpForce: -12.5,
    platformWidthBase: 160,
    gapBase: 100,
  },
  MEDIUM: {
    target: 100000,
    gravity: 0.58,
    moveSpeed: 0.75,
    maxSpeed: 9.0,
    jumpForce: -12.8,
    platformWidthBase: 120,
    gapBase: 110,
  },
  HARD: {
    target: 1000000,
    gravity: 0.68,
    moveSpeed: 0.62,
    maxSpeed: 7.5,
    jumpForce: -13.5,
    platformWidthBase: 90,
    gapBase: 120,
  }
};

export const WORLD_WIDTH = 10000000; 
export const WORLD_HEIGHT = 1200;

export const FRICTION = 0.82;
export const ICE_FRICTION = 0.992;
export const SLOW_FRICTION = 0.45;

export const COLORS = {
  SKY: '#bae6fd', 
  CLOUD: '#ffffff',
  GRASS: '#4ade80',
  BOUNCY: '#f472b6',
  MOVING: '#60a5fa',
  FRAGILE: '#fb923c', 
  BOOSTER: '#a855f7',
  ICE: '#99f6e4', 
  SLOW: '#94a3b8', 
  PLAYER: '#fbbf24',
  FINISH: '#ef4444', 
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Difficulty } from './types';
import { DIFFICULTY_CONFIG, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    cameraY: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
    difficulty: Difficulty.EASY,
    targetMeters: DIFFICULTY_CONFIG.EASY.target,
    isSelectingMode: true,
  });

  const [encouragement, setEncouragement] = useState("Choose your challenge to start.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number, difficulty: Difficulty) => {
    const config = DIFFICULTY_CONFIG[difficulty];
    const newPlatforms: Platform[] = [];

    // Scaling relative to the chosen difficulty's target
    const difficultyProgress = Math.min(1, Math.pow(currentMeters / (config.target * 0.1), 0.5)); 
    const extremeProgress = Math.min(1, currentMeters / (config.target * 0.5));

    const MAX_VERTICAL_UP = 80 + (difficultyProgress * 80); 
    const MAX_VERTICAL_DOWN = 130 + (difficultyProgress * 100);
    const baseWidth = config.platformWidthBase - (difficultyProgress * (config.platformWidthBase * 0.75)); 

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 300, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 300;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = Math.max(difficulty === Difficulty.HARD ? 15 : 40, baseWidth + Math.random() * 30);
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);

      nextY = Math.max(100, Math.min(950, nextY));

      const yDiff = lastY - nextY;
      let maxGap = (config.gapBase + 100) + (difficultyProgress * 160); 
      if (yDiff > 40) maxGap = (config.gapBase + 20) + (difficultyProgress * 110); 

      const gap = config.gapBase + Math.random() * (maxGap - config.gapBase);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      const pBouncy = 0.90 - (extremeProgress * 0.2);
      const pMoving = 0.80 - (extremeProgress * 0.3);
      const pFragile = 0.65 - (extremeProgress * 0.4);

      if (typeSeed > pBouncy) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > pMoving) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * (80 + difficultyProgress * 200);
        moveSpeed = 1.5 + Math.random() * (2.5 + extremeProgress * 4);
        nextX += moveRange / 2;
      } else if (typeSeed > pFragile) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = Math.max(8, 40 - (difficultyProgress * 35)); 
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const selectMode = (difficulty: Difficulty) => {
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const config = DIFFICULTY_CONFIG[difficulty];
    const initialPlatforms = generatePlatforms(0, 50, 0, difficulty);

    setGameState({
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      cameraY: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
      difficulty: difficulty,
      targetMeters: config.target,
      isSelectingMode: false,
    });
    setEncouragement(`Reach ${config.target.toLocaleString()}M. Let's go!`);
  };

  const resetGame = useCallback(() => {
    setGameState(prev => ({ ...prev, isSelectingMode: true }));
  }, []);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 18000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon || prev.isSelectingMode) return prev;

      const config = DIFFICULTY_CONFIG[prev.difficulty];
      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 30, prev.score, prev.difficulty);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1500);
      }

      let currentFriction = FRICTION;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = config.jumpForce * 1.6;
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 28; 
             newPlayer.vel.y = -4;
          } else if (currentP.type === PlatformType.ICE) {
            currentFriction = ICE_FRICTION;
          } else if (currentP.type === PlatformType.SLOW) {
            currentFriction = SLOW_FRICTION;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 12) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 12) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * config.moveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = config.maxSpeed * (newPlayer.vel.x > 18 ? 3.5 : 1.25);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3.5);
      } else {
        newPlayer.vel.y += config.gravity;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = config.jumpForce;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = config.jumpForce * 0.9;
          newPlayer.vel.x = -wallDirection * 10;
          keys.current['Space'] = false;
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - 400) - prev.cameraX) * 0.1;
      const targetCameraY = newPlayer.pos.y - window.innerHeight / 2;
      const cameraY = prev.cameraY + (targetCameraY - prev.cameraY) * 0.08;

      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > prev.cameraY + window.innerHeight + 200) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell after ${meters}m on ${prev.difficulty} mode.`;
      }

      if (meters >= prev.targetMeters) {
        isGameWon = true;
        pendingEncouragementContext.current = `CHAMPION! ${prev.difficulty} MODE CONQUERED!`;
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        cameraY,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        isSelectingMode={gameState.isSelectingMode}
        targetMeters={gameState.targetMeters}
        encouragement={encouragement}
        onRestart={resetGame}
        onSelectMode={selectMode}
      />
    </div>
  );
};

export default App;

