const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const STORAGE_KEY = 'sky_hops_v1_completions';

const App: React.FC = () => {
  const loadCompletions = (): Record<Difficulty, number> => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
