import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Difficulty } from './types';
import { DIFFICULTY_CONFIG, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const STORAGE_KEY = 'sky_hops_v1_completions';

const App: React.FC = () => {
  const loadCompletions = (): Record<Difficulty, number> => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to load completions", e);
    }
    return {
      [Difficulty.EASY]: 0,
      [Difficulty.MEDIUM]: 0,
      [Difficulty.HARD]: 0,
    };
  };

  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    cameraY: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
    difficulty: Difficulty.EASY,
    targetMeters: DIFFICULTY_CONFIG.EASY.target,
    isSelectingMode: true,
    completionCounts: loadCompletions(),
  });

  const [encouragement, setEncouragement] = useState("Choose your challenge to start.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number, difficulty: Difficulty) => {
    const config = DIFFICULTY_CONFIG[difficulty];
    const newPlatforms: Platform[] = [];

    const difficultyProgress = Math.min(1, Math.pow(currentMeters / (config.target * 0.1), 0.5)); 
    const extremeProgress = Math.min(1, currentMeters / (config.target * 0.5));

    const MAX_VERTICAL_UP = 80 + (difficultyProgress * 80); 
    const MAX_VERTICAL_DOWN = 130 + (difficultyProgress * 100);
    const baseWidth = config.platformWidthBase - (difficultyProgress * (config.platformWidthBase * 0.75)); 

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 300, 
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 300;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let width = Math.max(difficulty === Difficulty.HARD ? 15 : 40, baseWidth + Math.random() * 30);
      let nextY = lastY + (Math.random() * (MAX_VERTICAL_UP + MAX_VERTICAL_DOWN) - MAX_VERTICAL_UP);

      nextY = Math.max(100, Math.min(950, nextY));

      const yDiff = lastY - nextY;
      let maxGap = (config.gapBase + 100) + (difficultyProgress * 160); 
      if (yDiff > 40) maxGap = (config.gapBase + 20) + (difficultyProgress * 110); 

      const gap = config.gapBase + Math.random() * (maxGap - config.gapBase);
      let nextX = lastX + gap;

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      const pBouncy = 0.90 - (extremeProgress * 0.2);
      const pMoving = 0.80 - (extremeProgress * 0.3);
      const pFragile = 0.65 - (extremeProgress * 0.4);

      if (typeSeed > pBouncy) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > pMoving) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * (80 + difficultyProgress * 200);
        moveSpeed = 1.5 + Math.random() * (2.5 + extremeProgress * 4);
        nextX += moveRange / 2;
      } else if (typeSeed > pFragile) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = Math.max(8, 40 - (difficultyProgress * 35)); 
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const selectMode = (difficulty: Difficulty) => {
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const config = DIFFICULTY_CONFIG[difficulty];
    const initialPlatforms = generatePlatforms(0, 50, 0, difficulty);

    setGameState(prev => ({
      ...prev,
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      cameraY: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
      difficulty: difficulty,
      targetMeters: config.target,
      isSelectingMode: false,
    }));
    setEncouragement(`Reach ${config.target.toLocaleString()}M. Let's go!`);
  };

  const setInput = useCallback((key: string, active: boolean) => {
    keys.current[key] = active;
  }, []);

  const resetGame = useCallback(() => {
    setGameState(prev => ({ ...prev, isSelectingMode: true }));
  }, []);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 30000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon || prev.isSelectingMode) return prev;

      const config = DIFFICULTY_CONFIG[prev.difficulty];
      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;
      let updatedCompletionCounts = { ...prev.completionCounts };

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 30, prev.score, prev.difficulty);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1500);
      }

      let currentFriction = FRICTION;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 15 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = config.jumpForce * 1.6;
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 28; 
             newPlayer.vel.y = -4;
          } else if (currentP.type === PlatformType.ICE) {
            currentFriction = ICE_FRICTION;
          } else if (currentP.type === PlatformType.SLOW) {
            currentFriction = SLOW_FRICTION;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 12) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 12) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * config.moveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = config.maxSpeed * (newPlayer.vel.x > 18 ? 3.5 : 1.25);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3.5);
      } else {
        newPlayer.vel.y += config.gravity;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = config.jumpForce;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = config.jumpForce * 0.9;
          newPlayer.vel.x = -wallDirection * 10;
          keys.current['Space'] = false;
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - window.innerWidth * 0.3) - prev.cameraX) * 0.1;
      const targetCameraY = newPlayer.pos.y - window.innerHeight / 2;
      const cameraY = prev.cameraY + (targetCameraY - prev.cameraY) * 0.08;

      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > prev.cameraY + window.innerHeight + 200) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell after ${meters}m on ${prev.difficulty} mode.`;
      }

      if (meters >= prev.targetMeters && !prev.isGameWon) {
        isGameWon = true;
        updatedCompletionCounts[prev.difficulty] += 1;
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedCompletionCounts));
        pendingEncouragementContext.current = `CHAMPION! ${prev.difficulty} MODE CONQUERED!`;
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        cameraY,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18,
        completionCounts: updatedCompletionCounts,
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100 touch-none">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        isSelectingMode={gameState.isSelectingMode}
        targetMeters={gameState.targetMeters}
        encouragement={encouragement}
        completionCounts={gameState.completionCounts}
        onRestart={resetGame}
        onSelectMode={selectMode}
        onInput={setInput}
      />
    </div>
  );
};

