  const [showTouchControls, setShowTouchControls] = useState(false);

  useEffect(() => {
    // Show buttons if touch is detected OR if the screen is small (mobile/tablet sizes)
    const isTouch = 'ontouchstart' in window || navigator.maxTouchPoints > 0;
    const isSmallScreen = window.innerWidth < 1024;
    setShowTouchControls(isTouch || isSmallScreen);

    // Update on resize just in case
    const handleResize = () => {
      setShowTouchControls('ontouchstart' in window || navigator.maxTouchPoints > 0 || window.innerWidth < 1024);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const progress = Math.min(100, (score / targetMeters) * 100);

  const handleTouchAction = (key: string, active: boolean, e: React.TouchEvent | React.MouseEvent) => {
    if (e.cancelable) e.preventDefault();
    onInput(key, active);
  };

  return (
    <div className="fixed inset-0 pointer-events-none flex flex-col justify-between p-4 md:p-6 font-['Quicksand'] select-none overflow-hidden">
