          <div className="flex flex-col gap-2">
            <div className="bg-white/80 backdrop-blur-xl px-4 py-2 md:px-6 md:py-3 rounded-2xl shadow-xl border-b-4 border-pink-300 pointer-events-auto">
              <h1 className="text-xs md:text-xl font-bold text-pink-500 font-['Fredoka_One'] tracking-wide">DREAM HOPS</h1>
              <p className="text-gray-700 font-bold text-lg md:text-2xl tabular-nums">
