              </p>
            </div>

            <div className="w-32 md:w-64 h-3 md:h-4 bg-white/40 rounded-full border border-white overflow-hidden backdrop-blur-md">
              <div 
                className="h-full bg-gradient-to-r from-pink-400 via-purple-400 to-indigo-400 transition-all duration-700 ease-out shadow-[0_0_10px_rgba(255,182,193,0.5)]"
                style={{ width: `${progress}%` }}
              />
            </div>
          </div>

          <div className="bg-white/80 backdrop-blur-xl p-2 md:p-4 rounded-xl shadow-lg border-r-4 border-yellow-300 max-w-[140px] md:max-w-xs transition-all duration-300 pointer-events-auto">
            <p className="text-yellow-600 font-bold italic text-[9px] md:text-xs uppercase tracking-tighter mb-1">Spirit Guide</p>
            <p className="text-gray-700 font-medium text-[10px] md:text-sm leading-tight italic">"{encouragement}"</p>
          </div>
