import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const driftRef = useRef<{x: number, y: number, s: number}[]>([]);

  useEffect(() => {
    if (driftRef.current.length === 0) {
      for (let i = 0; i < 80; i++) {
        driftRef.current.push({
          x: Math.random() * 2000,
          y: Math.random() * 1200,
          s: Math.random() * 2 + 1
        });
      }
    }
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, cameraY, score, targetMeters } = gameState;

    // 1. Draw Cotton Candy Sky
    const progress = Math.min(1, score / targetMeters);
    const topColor = lerpColor('#ffdfd3', '#312e81', progress); // Peach -> Deep Indigo
    const midColor = lerpColor('#fff0f5', '#4c1d95', progress); // Lavender -> Purple
    const bottomColor = lerpColor('#f0f9ff', '#1e1b4b', progress); // Blue -> Midnight

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(0.5, midColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Drifting background elements
    ctx.save();
    ctx.translate((-cameraX * 0.05) % 2000, (-cameraY * 0.05) % 1200);
    ctx.fillStyle = progress > 0.7 ? '#ffffff' : '#fbcfe8';
    driftRef.current.forEach(d => {
      ctx.beginPath();
      ctx.arc(d.x, d.y, d.s, 0, Math.PI * 2);
      ctx.fill();
      // Tile background for seamless loop
      ctx.beginPath(); ctx.arc(d.x - 2000, d.y, d.s, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(d.x + 2000, d.y, d.s, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(d.x, d.y - 1200, d.s, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(d.x, d.y + 1200, d.s, 0, Math.PI * 2); ctx.fill();
    });
    ctx.restore();

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, -cameraY);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Drop Shadow
      ctx.fillStyle = 'rgba(0,0,0,0.06)';
      ctx.beginPath();
      ctx.roundRect(p.x + 5, p.y + 8, p.width, p.height, 16);
      ctx.fill();

      // Main Platform
      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 30);
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 16);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Platform Decorative Accents
      if (p.type === PlatformType.BOUNCY) {
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.beginPath();
        ctx.roundRect(p.x + 15, p.y + 8, p.width - 30, 6, 4);
        ctx.fill();
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player
    const drawW = player.isWallSliding ? player.width * 0.8 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.2 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 4 : -4) : 0;

    // Player Shadow
    ctx.fillStyle = 'rgba(0,0,0,0.1)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4 + xOffset, player.pos.y + 5, drawW, drawH, 14);
    ctx.fill();

    // Player Body
    ctx.fillStyle = COLORS.PLAYER;
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 14);
    ctx.fill();

    // Player Eyes
    const eyeDir = player.vel.x > 0 ? 6 : (player.vel.x < 0 ? -6 : 0);
    const eyeY = player.pos.y + 12;
    ctx.fillStyle = '#fff';
    ctx.beginPath(); ctx.arc(player.pos.x + 12 + eyeDir, eyeY + 4, 4.5, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(player.pos.x + 28 + eyeDir, eyeY + 4, 4.5, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#333';
    ctx.beginPath(); ctx.arc(player.pos.x + 12 + eyeDir + (eyeDir/3), eyeY + 4, 2, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(player.pos.x + 28 + eyeDir + (eyeDir/3), eyeY + 4, 2, 0, Math.PI * 2); ctx.fill();

    // Mouth
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2.5;
    ctx.lineCap = 'round';
    ctx.beginPath();
    const mouthX = player.pos.x + 20 + eyeDir;
    const mouthY = player.pos.y + 28;
    if (Math.abs(player.vel.y) > 5) {
        ctx.arc(mouthX, mouthY + 3, 5, 0, Math.PI); 
    } else {
        ctx.arc(mouthX, mouthY, 7, 0.25 * Math.PI, 0.75 * Math.PI);
    }
    ctx.stroke();

    ctx.restore();

  }, [gameState]);

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (Math.round(rr) << 16) + (Math.round(rg) << 8) + Math.round(rb)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full" />;
};

