import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Difficulty } from './types';
import { DIFFICULTY_CONFIG, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const STORAGE_KEY = 'sky_hops_v1_completions';

const App: React.FC = () => {
  const loadCompletions = (): Record<Difficulty, number> => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to load completions", e);
    }
    return {
      [Difficulty.EASY]: 0,
      [Difficulty.MEDIUM]: 0,
      [Difficulty.HARD]: 0,
    };
  };

  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    cameraY: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
    difficulty: Difficulty.EASY,
    targetMeters: DIFFICULTY_CONFIG.EASY.target,
    isSelectingMode: true,
    completionCounts: loadCompletions(),
  });

  const [encouragement, setEncouragement] = useState("Choose your challenge to start.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number, difficulty: Difficulty) => {
    const config = DIFFICULTY_CONFIG[difficulty];
    const newPlatforms: Platform[] = [];

    // Physical reach math
    const g = config.gravity;
    const vJump = Math.abs(config.jumpForce);
    const vMax = config.maxSpeed;

    // Max jump height = v^2 / 2g
    const hMaxReach = (vJump * vJump) / (2 * g);
    // Time to peak = v / g
    const tPeak = vJump / g;

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 450, // Friendlier start
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 450;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;

      // Ensure vertical climb is strictly less than max jump height (80% safety)
      const maxClimb = hMaxReach * 0.8;
      const verticalOffset = (Math.random() * (maxClimb + 250)) - maxClimb;
      let nextY = lastY + verticalOffset;

      // Clamp Y to playable area
      nextY = Math.max(150, Math.min(950, nextY));
      const deltaY = nextY - lastY; // Positive = jumping DOWN

      // Calculate time in air to reach that height difference
      // deltaY = v0*t + 0.5*g*t^2
      // 0.5*g*t^2 + v0*t - deltaY = 0
      // v0 is jumpForce (negative)
      let tAir = 0;
      if (deltaY < 0) {
        // Jumping UP
        const discriminant = (vJump * vJump) + (2 * g * deltaY);
        if (discriminant >= 0) {
          // Time to reach peak + time to fall back down to deltaY
          // Or just use the formula for landing on the way down
          tAir = (vJump + Math.sqrt(discriminant)) / g;
        } else {
          // Fallback if somehow math fails
          nextY = lastY - (hMaxReach * 0.5);
          tAir = tPeak;
        }
      } else {
        // Jumping DOWN or LEVEL
        // t = peak time + time to fall from peak to deltaY
        const hTotalFall = hMaxReach + deltaY;
        const tFall = Math.sqrt((2 * hTotalFall) / g);
        tAir = tPeak + tFall;
      }

      // Max horizontal reach = max velocity * air time
      const xReachMax = vMax * tAir;
      const safeMaxGap = xReachMax * 0.75; // 25% safety margin for humans
      const minGap = Math.max(80, config.gapBase);

      const gap = minGap + Math.random() * (Math.max(minGap + 20, safeMaxGap) - minGap);
      const nextX = lastX + gap;

      let width = config.platformWidthBase + Math.random() * 40;
      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      // Platform types based on difficulty and progression
      if (typeSeed > 0.9) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.83 && difficulty !== Difficulty.EASY) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 50 + Math.random() * 80;
        moveSpeed = 1.5 + Math.random() * 1.5;
      } else if (typeSeed > 0.75 && difficulty === Difficulty.HARD) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = 40; 
      }

      const newPlatform: Platform = {
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      };

      newPlatforms.push(newPlatform);
      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const selectMode = (difficulty: Difficulty) => {
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const config = DIFFICULTY_CONFIG[difficulty];
    const initialPlatforms = generatePlatforms(0, 40, 0, difficulty);

    setGameState(prev => ({
      ...prev,
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      cameraY: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
      difficulty: difficulty,
      targetMeters: config.target,
      isSelectingMode: false,
    }));
    setEncouragement(`Reach ${config.target.toLocaleString()}M. Sky's the limit!`);
  };

  const setInput = useCallback((key: string, active: boolean) => {
    keys.current[key] = active;
  }, []);

  const resetGame = useCallback(() => {
    setGameState(prev => ({ ...prev, isSelectingMode: true }));
  }, []);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 30000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon || prev.isSelectingMode) return prev;

      const config = DIFFICULTY_CONFIG[prev.difficulty];
      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;
      let updatedCompletionCounts = { ...prev.completionCounts };

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 25, prev.score, prev.difficulty);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 2000);
      }

      let currentFriction = FRICTION;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);
        const vOverlap = (newPlayer.pos.y + newPlayer.height > currentP.y && newPlayer.pos.y < currentP.y + currentP.height);

        // Platform collision
        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > currentP.y &&
          newPlayer.pos.y + newPlayer.height < currentP.y + currentP.height + 25 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = currentP.y - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = config.jumpForce * 1.8;
            for(let i=0; i<8; i++) {
              newParticles.push({
                x: newPlayer.pos.x + newPlayer.width/2,
                y: currentP.y,
                vx: (Math.random() - 0.5) * 8,
                vy: -Math.random() * 8,
                life: 1,
                color: COLORS.BOUNCY,
                size: Math.random() * 4 + 2
              });
            }
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        // Wall detection for wall jumping
        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 15) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 15) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * config.moveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = config.maxSpeed;
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3.2);
      } else {
        newPlayer.vel.y += config.gravity;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = config.jumpForce;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = config.jumpForce * 0.95;
          newPlayer.vel.x = -wallDirection * 12;
          keys.current['Space'] = false;
        }
      }

      // Smooth camera with target leading
      const cameraX = prev.cameraX + ((newPlayer.pos.x - window.innerWidth * 0.35) - prev.cameraX) * 0.1;
      const targetCameraY = newPlayer.pos.y - window.innerHeight / 2;
      const cameraY = prev.cameraY + (targetCameraY - prev.cameraY) * 0.08;

      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > prev.cameraY + window.innerHeight + 600) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell after ${meters}m on ${prev.difficulty}.`;
      }

      if (meters >= prev.targetMeters && !prev.isGameWon) {
        isGameWon = true;
        updatedCompletionCounts[prev.difficulty] += 1;
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedCompletionCounts));
        pendingEncouragementContext.current = `WON ${prev.difficulty} MODE!`;
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.03
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        cameraY,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: Math.abs(newPlayer.vel.x) > 8.5,
        completionCounts: updatedCompletionCounts,
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100 touch-none">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        isSelectingMode={gameState.isSelectingMode}
        targetMeters={gameState.targetMeters}
        encouragement={encouragement}
        completionCounts={gameState.completionCounts}
        onRestart={resetGame}
        onSelectMode={selectMode}
        onInput={setInput}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const starsRef = useRef<{x: number, y: number, s: number}[]>([]);

  useEffect(() => {
    if (starsRef.current.length === 0) {
      for (let i = 0; i < 60; i++) {
        starsRef.current.push({
          x: Math.random() * 2000,
          y: Math.random() * 1200,
          s: Math.random() * 3 + 1
        });
      }
    }
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, cameraY, score, highSpeedMode, targetMeters } = gameState;

    // 1. Draw Cotton Candy Sky
    const progress = Math.min(1, score / targetMeters);
    const topColor = lerpColor(COLORS.SKY_TOP, '#312e81', progress);
    const bottomColor = lerpColor(COLORS.SKY_BOTTOM, '#1e1b4b', progress);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Drifting petals/stars
    ctx.save();
    ctx.translate((-cameraX * 0.05) % 2000, (-cameraY * 0.05) % 1200);
    ctx.fillStyle = progress > 0.8 ? '#fff' : '#fbcfe8';
    starsRef.current.forEach(star => {
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.s, 0, Math.PI * 2);
      ctx.fill();
      // Tile background
      ctx.beginPath(); ctx.arc(star.x - 2000, star.y, star.s, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(star.x + 2000, star.y, star.s, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(star.x, star.y - 1200, star.s, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(star.x, star.y + 1200, star.s, 0, Math.PI * 2); ctx.fill();
    });
    ctx.restore();

    // 2. Parallax Layers
    const drawParallaxClouds = (pX: number, pY: number, color: string, scale: number, opacity: number) => {
        ctx.save();
        ctx.translate(-cameraX * pX, -cameraY * pY);
        ctx.fillStyle = color;
        ctx.globalAlpha = opacity;
        const spacing = 1200;
        for (let i = -1; i < 5; i++) {
            const xPos = (Math.floor(cameraX * pX / spacing) * spacing) + (i * spacing);
            const yPos = (i * 350) % 900;
            drawCloud(ctx, xPos, yPos, scale);
        }
        ctx.restore();
    };

    if (progress < 0.9) {
        drawParallaxClouds(0.1, 0.05, '#ffffff', 0.5, 0.2);
        drawParallaxClouds(0.2, 0.1, '#ffffff', 0.8, 0.4);
    }

    // 3. Draw World
    ctx.save();
    ctx.translate(-cameraX, -cameraY);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Platform Shadow
      ctx.fillStyle = 'rgba(0,0,0,0.06)';
      ctx.beginPath();
      ctx.roundRect(p.x + 6, p.y + 10, p.width, p.height, 16);
      ctx.fill();

      // Platform Body
      ctx.fillStyle = p.color;
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 40);
      }
      ctx.beginPath();
      ctx.roundRect(p.x, p.y, p.width, p.height, 16);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      // Platform Accents
      if (p.type === PlatformType.BOUNCY) {
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.beginPath();
        ctx.roundRect(p.x + 15, p.y + 8, p.width - 30, 6, 4);
        ctx.fill();
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player Rendering (Rounded and friendly)
    const drawW = player.isWallSliding ? player.width * 0.8 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.2 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 4 : -4) : 0;

    // Player Shadow
    ctx.fillStyle = 'rgba(0,0,0,0.1)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 4 + xOffset, player.pos.y + 5, drawW, drawH, 14);
    ctx.fill();

    // Player Body
    ctx.fillStyle = COLORS.PLAYER;
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 14);
    ctx.fill();

    // Player Face
    const eyeDir = player.vel.x > 0 ? 6 : (player.vel.x < 0 ? -6 : 0);
    const eyeBaseY = player.pos.y + 12;
    ctx.fillStyle = '#fff';
    ctx.beginPath(); ctx.arc(player.pos.x + 12 + eyeDir, eyeBaseY + 4, 4.5, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(player.pos.x + 28 + eyeDir, eyeBaseY + 4, 4.5, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = '#333';
    ctx.beginPath(); ctx.arc(player.pos.x + 12 + eyeDir + (eyeDir/3), eyeBaseY + 4, 2, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.arc(player.pos.x + 28 + eyeDir + (eyeDir/3), eyeBaseY + 4, 2, 0, Math.PI * 2); ctx.fill();

    // Mouth
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2.5;
    ctx.lineCap = 'round';
    ctx.beginPath();
    const mouthY = player.pos.y + 28;
    const mouthX = player.pos.x + 20 + eyeDir;
    if (Math.abs(player.vel.y) > 4.5) {
        ctx.arc(mouthX, mouthY + 3, 5, 0, Math.PI); 
    } else {
        ctx.arc(mouthX, mouthY, 7, 0.25 * Math.PI, 0.75 * Math.PI);
    }
    ctx.stroke();

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.beginPath();
    ctx.arc(x, y, 30 * scale, 0, Math.PI * 2);
    ctx.arc(x + 40 * scale, y - 10 * scale, 50 * scale, 0, Math.PI * 2);
    ctx.arc(x + 80 * scale, y, 35 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (Math.round(rr) << 16) + (Math.round(rg) << 8) + Math.round(rb)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full" />;
};

export default GameCanvas;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Difficulty } from './types';
import { DIFFICULTY_CONFIG, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const STORAGE_KEY = 'sky_hops_v1_completions';

const App: React.FC = () => {
  const loadCompletions = (): Record<Difficulty, number> => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to load completions", e);
    }
    return {
      [Difficulty.EASY]: 0,
      [Difficulty.MEDIUM]: 0,
      [Difficulty.HARD]: 0,
    };
  };

  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    cameraY: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
    difficulty: Difficulty.EASY,
    targetMeters: DIFFICULTY_CONFIG.EASY.target,
    isSelectingMode: true,
    completionCounts: loadCompletions(),
  });

  const [encouragement, setEncouragement] = useState("Choose your challenge to start.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  /**
   * Generates a sequence of platforms that are mathematically guaranteed to be reachable.
   */
  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number, difficulty: Difficulty) => {
    const config = DIFFICULTY_CONFIG[difficulty];
    const newPlatforms: Platform[] = [];

    // Physics constants for reach calculation
    const g = config.gravity;
    const vJump = Math.abs(config.jumpForce);
    const vMax = config.maxSpeed;

    // Safety factor (0.8 means the player only needs 80% of their physical capability)
    const safety = 0.8;

    // Peak height the player can jump: H = v^2 / 2g
    const hMaxReach = (vJump * vJump) / (2 * g);
    // Time to reach the peak: t = v / g
    const tPeak = vJump / g;

    let lastX = startX;
    let lastY = 450;

    // Initial platform
    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 400, // Generous start
        height: 100, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS 
      });
      lastX = 400;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;

      // 1. Determine next height (Y)
      // Must be within [lastY - hMaxReach * safety, some reasonable drop]
      const maxClimb = hMaxReach * safety;
      const verticalOffset = (Math.random() * (maxClimb + 300)) - maxClimb;
      let nextY = lastY + verticalOffset;

      // Clamp to screen bounds
      nextY = Math.max(150, Math.min(950, nextY));
      const dy = nextY - lastY; // Positive dy means the next platform is LOWER

      // 2. Calculate time in air to reach that height
      // Kinematics: dy = u*t + 0.5*g*t^2 -> 0.5*g*t^2 - vJump*t - dy = 0 (using -vJump because jump is up)
      // Since we want to land ON the platform (on the way down for better feel),
      // we calculate the total time to peak + time to fall from peak to dy.

      let tAir = 0;
      if (dy < 0) {
        // Jumping UP
        // Peak is higher than the target platform.
        // Time to reach peak + time to fall from peak (hMaxReach) to target platform (hMaxReach - |dy|)
        const fallDist = hMaxReach + dy; // dy is negative, so hMaxReach - dist_above
        const tFall = Math.sqrt((2 * Math.max(0, fallDist)) / g);
        tAir = tPeak + tFall;
      } else {
        // Jumping LEVEL or DOWN
        // Time to reach peak + time to fall from peak to target platform (hMaxReach + dy)
        const fallDist = hMaxReach + dy;
        const tFall = Math.sqrt((2 * fallDist) / g);
        tAir = tPeak + tFall;
      }

      // 3. Determine horizontal gap based on air time
      // Max possible X = horizontal speed * time in air
      const xReachMax = vMax * tAir;
      const safeMaxGap = xReachMax * safety;
      const minGap = Math.max(100, config.gapBase);

      // If safeMaxGap is somehow smaller than minGap (extreme heights), adjust
      const gap = minGap + Math.random() * (Math.max(minGap + 10, safeMaxGap) - minGap);
      const nextX = lastX + gap;

      // 4. Platform properties
      const difficultyProgress = Math.min(1, currentMeters / config.target);
      let width = config.platformWidthBase - (difficultyProgress * 30) + Math.random() * 40;
      width = Math.max(60, width);

      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      // Assign type while preserving design
      if (typeSeed > 0.92) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.85 && difficulty !== Difficulty.EASY) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 60 + Math.random() * 100;
        moveSpeed = 1.2 + Math.random() * 2;
      } else if (typeSeed > 0.78 && difficulty === Difficulty.HARD) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = 35; 
      }

      newPlatforms.push({
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false
      });

      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const selectMode = (difficulty: Difficulty) => {
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const config = DIFFICULTY_CONFIG[difficulty];
    const initialPlatforms = generatePlatforms(0, 45, 0, difficulty);

    setGameState(prev => ({
      ...prev,
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      cameraY: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
      difficulty: difficulty,
      targetMeters: config.target,
      isSelectingMode: false,
    }));
    setEncouragement(`Goal: ${config.target.toLocaleString()}M. Every jump is possible!`);
  };

  const setInput = useCallback((key: string, active: boolean) => {
    keys.current[key] = active;
  }, []);

  const resetGame = useCallback(() => {
    setGameState(prev => ({ ...prev, isSelectingMode: true }));
  }, []);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 30000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon || prev.isSelectingMode) return prev;

      const config = DIFFICULTY_CONFIG[prev.difficulty];
      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;
      let updatedCompletionCounts = { ...prev.completionCounts };

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 3500 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 25, prev.score, prev.difficulty);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 1800);
      }

      let currentFriction = FRICTION;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

