   * Generates platforms that are mathematically GUARANTEED to be reachable.
   * Now includes organic "heightMap" and "bottomMap" for non-flat terrain.
   */
  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number, difficulty: Difficulty) => {
    const config = DIFFICULTY_CONFIG[difficulty];
    const newPlatforms: Platform[] = [];

    const g = config.gravity;
    const vJump = Math.abs(config.jumpForce);
    const vMax = config.maxSpeed;
    const horizontalSafety = 0.5;
    const hMaxReach = (vJump * vJump) / (2 * g);
    const tPeak = vJump / g;

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 750, 
        height: 120, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS,
        heightMap: Array(10).fill(0),
        bottomMap: Array(10).fill(80)
      });
      lastX = 750;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      if (typeSeed > 0.93) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.86 && difficulty !== Difficulty.EASY) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 40 + Math.random() * 70;
        moveSpeed = 0.8 + Math.random() * 1.2;
      } else if (typeSeed > 0.80 && difficulty === Difficulty.HARD) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = 50; 
      }

      // Vertical Climb restricted to 42% for 100% reachability
      const maxClimb = hMaxReach * 0.42;
      const verticalOffset = (Math.random() * (maxClimb + 300)) - maxClimb;
      let nextY = lastY + verticalOffset;
      nextY = Math.max(250, Math.min(850, nextY));
      const dy = nextY - lastY;

      const hFall = hMaxReach + dy;
      let tAir = tPeak;
      if (hFall > 0) tAir += Math.sqrt((2 * hFall) / g);

      const vEffective = vMax * 0.85;
      const xReachMax = vEffective * tAir;
      const reachableBudget = xReachMax - (moveRange * 2.0);
      const safeMaxGap = Math.max(140, reachableBudget * horizontalSafety);
      const minGap = Math.max(130, config.gapBase);
      const gap = minGap + Math.random() * (Math.max(minGap + 10, safeMaxGap) - minGap);
      const nextX = lastX + gap;

      const progress = Math.min(1, currentMeters / config.target);
      let width = config.platformWidthBase - (progress * 25) + Math.random() * 20;
      width = Math.max(110, width); 

      // Create Terrain Maps
      const segments = Math.floor(width / 20);
      const heightMap: number[] = [];
      const bottomMap: number[] = [];
      for (let s = 0; s <= segments; s++) {
        // Height map creates non-flat top surface. 
        // Offsets are kept small (0-15px) and negative (downward) to ensure jumps remain possible.
        heightMap.push(Math.random() * 15);
        // Bottom map creates craggy island look
        bottomMap.push(40 + Math.random() * 60);
      }

      newPlatforms.push({
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false,
        heightMap,
        bottomMap
      });

      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const selectMode = (difficulty: Difficulty) => {
