        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 15) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 15) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * config.moveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = config.maxSpeed * (newPlayer.vel.x > 18 ? 2.5 : 1.25);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3.0);
      } else {
        newPlayer.vel.y += config.gravity;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = config.jumpForce;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = config.jumpForce * 0.95;
          newPlayer.vel.x = -wallDirection * 11;
          keys.current['Space'] = false;
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - window.innerWidth * 0.35) - prev.cameraX) * 0.1;
      const targetCameraY = newPlayer.pos.y - window.innerHeight / 2;
      const cameraY = prev.cameraY + (targetCameraY - prev.cameraY) * 0.08;

      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > prev.cameraY + window.innerHeight + 700) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell at ${meters}m.`;
      }

      if (meters >= prev.targetMeters && !prev.isGameWon) {
        isGameWon = true;
        updatedCompletionCounts[prev.difficulty] += 1;
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedCompletionCounts));
        pendingEncouragementContext.current = `WON ${prev.difficulty}!`;
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        cameraY,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18,
        completionCounts: updatedCompletionCounts,
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100 touch-none">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        isSelectingMode={gameState.isSelectingMode}
        targetMeters={gameState.targetMeters}
        encouragement={encouragement}
        completionCounts={gameState.completionCounts}
        onRestart={resetGame}
        onSelectMode={selectMode}
        onInput={setInput}
      />
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { GameState, PlatformType } from '../types';
import { COLORS } from '../constants';

interface GameCanvasProps {
  gameState: GameState;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ gameState }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const { player, platforms, particles, cameraX, cameraY, score, highSpeedMode, targetMeters } = gameState;

    // 1. Draw Background
    const skyTransition = Math.min(1, score / targetMeters);
    const topColor = lerpColor('#7dd3fc', '#020617', skyTransition);
    const bottomColor = lerpColor('#e0f2fe', '#1e293b', skyTransition);

    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, topColor);
    gradient.addColorStop(1, bottomColor);
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Parallax
    ctx.save();
    ctx.translate(-cameraX * 0.2, -cameraY * 0.1);
    const cloudCount = 20;
    for (let i = 0; i < cloudCount; i++) {
        const xPos = (Math.floor(cameraX * 0.2 / 800) * 800) + (i * 800);
        const yPos = (i * 200) % 1000;
        if (skyTransition < 0.85) {
            drawCloud(ctx, xPos + 100, yPos, 0.6 + (i % 3) * 0.4);
        } else {
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(xPos + (i * 157) % 800, yPos, 1.5, 0, Math.PI * 2);
            ctx.fill();
        }
    }
    ctx.restore();

    // Speed Lines
    if (highSpeedMode) {
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
      ctx.lineWidth = 1;
      for(let i=0; i<30; i++) {
        const x = (Date.now() + i * 150) % canvas.width;
        const y = (i * 37) % canvas.height;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + 120, y);
        ctx.stroke();
      }
    }

    // 2. Draw World
    ctx.save();
    ctx.translate(-cameraX, -cameraY);

    // Platforms
    platforms.forEach(p => {
      if (p.type === PlatformType.FRAGILE && p.decay !== undefined && p.decay <= 0) return;

      // Draw non-flat island shape
      if (p.heightMap && p.bottomMap) {
        ctx.save();
        if (p.type === PlatformType.FRAGILE && p.decay !== undefined) {
          ctx.globalAlpha = Math.max(0, p.decay / 30);
        }

        // Rock Bottom
        ctx.fillStyle = skyTransition > 0.6 ? '#334155' : '#94a3b8';
        ctx.beginPath();
        const segW = p.width / (p.heightMap.length - 1);
        ctx.moveTo(p.x, p.y + p.heightMap[0]);
        for(let i=1; i < p.bottomMap.length; i++) {
          ctx.lineTo(p.x + i * segW, p.y + p.bottomMap[i]);
        }
        ctx.lineTo(p.x + p.width, p.y + p.heightMap[p.heightMap.length-1]);
        ctx.closePath();
        ctx.fill();

        // Surface Body
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y + p.heightMap[0]);
        for(let i=1; i < p.heightMap.length; i++) {
          ctx.lineTo(p.x + i * segW, p.y + p.heightMap[i]);
        }
        // Connect to bottom logic
        ctx.lineTo(p.x + p.width, p.y + 20);
        ctx.lineTo(p.x, p.y + 20);
        ctx.closePath();
        ctx.fill();

        // Surface Accent (Grass/Detail)
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(p.x, p.y + p.heightMap[0]);
        for(let i=1; i < p.heightMap.length; i++) {
          ctx.lineTo(p.x + i * segW, p.y + p.heightMap[i]);
        }
        ctx.stroke();

        // Decorative bits
        if (p.type === PlatformType.NORMAL || p.type === PlatformType.BOOSTER) {
          ctx.fillStyle = 'rgba(255,255,255,0.4)';
          for (let i = 0; i < p.heightMap.length; i+=2) {
             const bx = p.x + i * segW;
             const by = p.y + p.heightMap[i];
             ctx.beginPath();
             ctx.arc(bx, by - 2, 2, 0, Math.PI * 2);
             ctx.fill();
          }
        }

        ctx.restore();
      } else {
        // Fallback for flat platforms (rect style)
        ctx.fillStyle = 'rgba(0,0,0,0.1)';
        ctx.beginPath();
        ctx.roundRect(p.x + 4, p.y + 6, p.width, p.height, 10);
        ctx.fill();

        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.roundRect(p.x, p.y, p.width, p.height, 10);
        ctx.fill();
      }

      // Accents for specific types
      if (p.type === PlatformType.BOUNCY) {
        ctx.strokeStyle = '#fbcfe8';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.roundRect(p.x, p.y, p.width, 10, 5);
        ctx.stroke();
      } else if (p.type === PlatformType.BOOSTER) {
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        const arrowCount = Math.max(1, Math.floor(p.width / 25));
        for(let i=0; i<arrowCount; i++) {
          const arrowX = p.x + 10 + i * 25;
          ctx.beginPath();
          ctx.moveTo(arrowX, p.y + 10); ctx.lineTo(arrowX + 10, p.y + 17); ctx.lineTo(arrowX, p.y + 25);
          ctx.fill();
        }
      }
    });

    // Particles
    particles.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // Player Rendering
    const drawW = player.isWallSliding ? player.width * 0.85 : player.width;
    const drawH = player.isWallSliding ? player.height * 1.15 : player.height;
    const xOffset = player.isWallSliding ? (player.vel.x > 0 ? 3 : -3) : 0;

    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.beginPath();
    ctx.roundRect(player.pos.x + 3 + xOffset, player.pos.y + 4, drawW, drawH, 10);
    ctx.fill();

    ctx.fillStyle = COLORS.PLAYER;
    if (highSpeedMode) ctx.fillStyle = '#fef3c7'; 
    ctx.beginPath();
    ctx.roundRect(player.pos.x + (player.width - drawW)/2 + xOffset, player.pos.y + (player.height - drawH), drawW, drawH, 10);
    ctx.fill();

    // Face details
    const eyeDir = player.vel.x > 0 ? 4 : (player.vel.x < 0 ? -4 : 0);
    const eyeBaseY = player.pos.y + 12;
    ctx.fillStyle = '#fff';
    ctx.fillRect(player.pos.x + 8 + eyeDir, eyeBaseY, 8, 8);
    ctx.fillRect(player.pos.x + 24 + eyeDir, eyeBaseY, 8, 8);
    ctx.fillStyle = '#000';
    ctx.fillRect(player.pos.x + 11 + eyeDir, eyeBaseY + 3, 3, 3);
    ctx.fillRect(player.pos.x + 27 + eyeDir, eyeBaseY + 3, 3, 3);

    // Mouth
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 2;
    ctx.beginPath();
    const mouthY = player.pos.y + 28;
    const mouthX = player.pos.x + 20 + eyeDir;

    if (Math.abs(player.vel.y) > 3) {
        ctx.arc(mouthX, mouthY, 4, 0, Math.PI * 2); 
    } else if (Math.abs(player.vel.x) > 2) {
        ctx.moveTo(mouthX - 5, mouthY);
        ctx.lineTo(mouthX + 5, mouthY);
    } else {
        ctx.arc(mouthX, mouthY - 2, 5, 0.1 * Math.PI, 0.9 * Math.PI);
    }
    ctx.stroke();

    ctx.restore();

  }, [gameState]);

  const drawCloud = (ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) => {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
    ctx.beginPath();
    ctx.arc(x, y, 30 * scale, 0, Math.PI * 2);
    ctx.arc(x + 40 * scale, y - 10 * scale, 50 * scale, 0, Math.PI * 2);
    ctx.arc(x + 80 * scale, y, 35 * scale, 0, Math.PI * 2);
    ctx.fill();
  };

  const lerpColor = (a: string, b: string, amount: number) => {
    const ah = parseInt(a.replace(/#/g, ''), 16),
        ar = ah >> 16, ag = ah >> 8 & 0xff, ab = ah & 0xff,
        bh = parseInt(b.replace(/#/g, ''), 16),
        br = bh >> 16, bg = bh >> 8 & 0xff, bb = bh & 0xff,
        rr = ar + amount * (br - ar),
        rg = ag + amount * (bg - ag),
        rb = ab + amount * (bb - ab);
    return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + (rb | 0)).toString(16).slice(1);
  };

  return <canvas ref={canvasRef} className="block w-full h-full cursor-none" />;
};

export default GameCanvas;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameState, Player, Platform, PlatformType, Difficulty } from './types';
import { DIFFICULTY_CONFIG, FRICTION, ICE_FRICTION, SLOW_FRICTION, COLORS, WORLD_HEIGHT } from './constants';
import { getEncouragement } from './services/geminiService';

const INITIAL_PLAYER: Player = {
  pos: { x: 50, y: 300 },
  vel: { x: 0, y: 0 },
  width: 40,
  height: 40,
  isGrounded: false,
  jumpCount: 0,
  isWallSliding: false,
  lastWallJumpDir: 0,
};

const STORAGE_KEY = 'sky_hops_v1_completions';

const App: React.FC = () => {
  const loadCompletions = (): Record<Difficulty, number> => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to load completions", e);
    }
    return {
      [Difficulty.EASY]: 0,
      [Difficulty.MEDIUM]: 0,
      [Difficulty.HARD]: 0,
    };
  };

  const [gameState, setGameState] = useState<GameState>({
    player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
    platforms: [],
    particles: [],
    cameraX: 0,
    cameraY: 0,
    score: 0,
    isGameOver: false,
    isGameWon: false,
    distanceReached: 0,
    highSpeedMode: false,
    difficulty: Difficulty.EASY,
    targetMeters: DIFFICULTY_CONFIG.EASY.target,
    isSelectingMode: true,
    completionCounts: loadCompletions(),
  });

  const [encouragement, setEncouragement] = useState("Choose your challenge to start.");
  const lastEncouragementTime = useRef(0);
  const keys = useRef<{ [key: string]: boolean }>({});
  const pendingEncouragementContext = useRef<string | null>(null);
  const lastGeneratedX = useRef(0);
  const platformIdCounter = useRef(0);

  /**
   * Generates platforms that are mathematically GUARANTEED to be reachable.
   * Now includes organic "heightMap" and "bottomMap" for non-flat terrain.
   */
  const generatePlatforms = useCallback((startX: number, count: number, currentMeters: number, difficulty: Difficulty) => {
    const config = DIFFICULTY_CONFIG[difficulty];
    const newPlatforms: Platform[] = [];

    const g = config.gravity;
    const vJump = Math.abs(config.jumpForce);
    const vMax = config.maxSpeed;
    const horizontalSafety = 0.5;
    const hMaxReach = (vJump * vJump) / (2 * g);
    const tPeak = vJump / g;

    let lastX = startX;
    let lastY = 450;

    if (startX === 0) {
      newPlatforms.push({ 
        id: 'start', 
        x: 0, 
        y: 450, 
        width: 750, 
        height: 120, 
        type: PlatformType.NORMAL, 
        color: COLORS.GRASS,
        heightMap: Array(10).fill(0),
        bottomMap: Array(10).fill(80)
      });
      lastX = 750;
    }

    for (let i = 0; i < count; i++) {
      const typeSeed = Math.random();
      let type = PlatformType.NORMAL;
      let color = COLORS.CLOUD;
      let moveRange = 0;
      let moveSpeed = 0;
      let decay = 0;

      if (typeSeed > 0.93) {
        type = PlatformType.BOUNCY;
        color = COLORS.BOUNCY;
      } else if (typeSeed > 0.86 && difficulty !== Difficulty.EASY) {
        type = PlatformType.MOVING;
        color = COLORS.MOVING;
        moveRange = 40 + Math.random() * 70;
        moveSpeed = 0.8 + Math.random() * 1.2;
      } else if (typeSeed > 0.80 && difficulty === Difficulty.HARD) {
        type = PlatformType.FRAGILE;
        color = COLORS.FRAGILE;
        decay = 50; 
      }

      // Vertical Climb restricted to 42% for 100% reachability
      const maxClimb = hMaxReach * 0.42;
      const verticalOffset = (Math.random() * (maxClimb + 300)) - maxClimb;
      let nextY = lastY + verticalOffset;
      nextY = Math.max(250, Math.min(850, nextY));
      const dy = nextY - lastY;

      const hFall = hMaxReach + dy;
      let tAir = tPeak;
      if (hFall > 0) tAir += Math.sqrt((2 * hFall) / g);

      const vEffective = vMax * 0.85;
      const xReachMax = vEffective * tAir;
      const reachableBudget = xReachMax - (moveRange * 2.0);
      const safeMaxGap = Math.max(140, reachableBudget * horizontalSafety);
      const minGap = Math.max(130, config.gapBase);
      const gap = minGap + Math.random() * (Math.max(minGap + 10, safeMaxGap) - minGap);
      const nextX = lastX + gap;

      const progress = Math.min(1, currentMeters / config.target);
      let width = config.platformWidthBase - (progress * 25) + Math.random() * 20;
      width = Math.max(110, width); 

      // Create Terrain Maps
      const segments = Math.floor(width / 20);
      const heightMap: number[] = [];
      const bottomMap: number[] = [];
      for (let s = 0; s <= segments; s++) {
        // Height map creates non-flat top surface. 
        // Offsets are kept small (0-15px) and negative (downward) to ensure jumps remain possible.
        heightMap.push(Math.random() * 15);
        // Bottom map creates craggy island look
        bottomMap.push(40 + Math.random() * 60);
      }

      newPlatforms.push({
        id: `p-${platformIdCounter.current++}`,
        x: nextX,
        y: nextY,
        width,
        height: 35,
        type,
        color,
        moveRange,
        moveSpeed,
        initialX: nextX,
        decay,
        isTouched: false,
        heightMap,
        bottomMap
      });

      lastX = nextX + width;
      lastY = nextY;
    }

    lastGeneratedX.current = lastX;
    return newPlatforms;
  }, []);

  const selectMode = (difficulty: Difficulty) => {
    lastGeneratedX.current = 0;
    platformIdCounter.current = 0;
    const config = DIFFICULTY_CONFIG[difficulty];
    const initialPlatforms = generatePlatforms(0, 60, 0, difficulty);

    setGameState(prev => ({
      ...prev,
      player: JSON.parse(JSON.stringify(INITIAL_PLAYER)),
      platforms: initialPlatforms,
      particles: [],
      cameraX: 0,
      cameraY: 0,
      score: 0,
      isGameOver: false,
      isGameWon: false,
      distanceReached: 0,
      highSpeedMode: false,
      difficulty: difficulty,
      targetMeters: config.target,
      isSelectingMode: false,
    }));
    setEncouragement(`Reach ${config.target.toLocaleString()}M. Every terrain is traversable!`);
  };

  const setInput = useCallback((key: string, active: boolean) => {
    keys.current[key] = active;
  }, []);

  const resetGame = useCallback(() => {
    setGameState(prev => ({ 
      ...prev, 
      isSelectingMode: true,
      isGameOver: false,
      isGameWon: false
    }));
  }, []);

  const updateGeminiEncouragement = useCallback(async (context: string) => {
    const now = Date.now();
    if (now - lastEncouragementTime.current > 30000) {
      lastEncouragementTime.current = now;
      const text = await getEncouragement(context);
      setEncouragement(text);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (pendingEncouragementContext.current) {
        const ctx = pendingEncouragementContext.current;
        pendingEncouragementContext.current = null;
        updateGeminiEncouragement(ctx);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [updateGeminiEncouragement]);

  const handleKeyDown = (e: KeyboardEvent) => { keys.current[e.code] = true; };
  const handleKeyUp = (e: KeyboardEvent) => { keys.current[e.code] = false; };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const update = useCallback(() => {
    setGameState(prev => {
      if (prev.isGameOver || prev.isGameWon || prev.isSelectingMode) return prev;

      const config = DIFFICULTY_CONFIG[prev.difficulty];
      const newPlayer: Player = { 
        ...prev.player,
        pos: { ...prev.player.pos },
        vel: { ...prev.player.vel }
      };

      const newParticles = [...prev.particles];
      let isGameWon = prev.isGameWon;
      let isGameOver = prev.isGameOver;
      let updatedCompletionCounts = { ...prev.completionCounts };

      let newPlatformsList = [...prev.platforms];
      if (newPlayer.pos.x + 4000 > lastGeneratedX.current) {
        const appended = generatePlatforms(lastGeneratedX.current, 30, prev.score, prev.difficulty);
        newPlatformsList = [...newPlatformsList, ...appended];
        newPlatformsList = newPlatformsList.filter(p => p.x + p.width > prev.cameraX - 2500);
      }

      let currentFriction = FRICTION;
      let grounded = false;
      let touchingWall = false;
      let wallDirection = 0; 

      const updatedPlatforms = newPlatformsList.map(p => {
        let currentP = { ...p };
        if (p.type === PlatformType.MOVING && p.moveRange && p.moveSpeed && p.initialX !== undefined) {
          const offsetX = Math.sin(Date.now() / 1000 * p.moveSpeed) * p.moveRange;
          currentP.x = p.initialX + offsetX;
        }

        if (currentP.isTouched && currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined) {
          currentP.decay -= 1;
        }

        const hOverlap = (newPlayer.pos.x + newPlayer.width > currentP.x && newPlayer.pos.x < currentP.x + currentP.width);

        // Calculate dynamic surface height if heightMap exists
        let surfaceY = currentP.y;
        if (currentP.heightMap && hOverlap) {
          const relX = (newPlayer.pos.x + newPlayer.width / 2) - currentP.x;
          const mapIdx = Math.max(0, Math.min(currentP.heightMap.length - 1, Math.floor((relX / currentP.width) * (currentP.heightMap.length - 1))));
          surfaceY += currentP.heightMap[mapIdx];
        }

        const vOverlap = (newPlayer.pos.y + newPlayer.height > surfaceY && newPlayer.pos.y < surfaceY + currentP.height + 25);

        if (
          hOverlap &&
          newPlayer.pos.y + newPlayer.height > surfaceY &&
          newPlayer.pos.y + newPlayer.height < surfaceY + 35 &&
          newPlayer.vel.y >= 0 &&
          !(currentP.type === PlatformType.FRAGILE && currentP.decay !== undefined && currentP.decay <= 0)
        ) {
          newPlayer.pos.y = surfaceY - newPlayer.height;

          if (currentP.type === PlatformType.BOUNCY) {
            newPlayer.vel.y = config.jumpForce * 1.85;
          } else if (currentP.type === PlatformType.BOOSTER) {
             newPlayer.vel.x = 23; 
             newPlayer.vel.y = -5;
          }

          if (currentP.type === PlatformType.FRAGILE) {
            currentP.isTouched = true;
          }

          if (newPlayer.vel.y > 0) newPlayer.vel.y = 0;
          grounded = true;
        }

        if (vOverlap && !grounded) {
          if (newPlayer.pos.x + newPlayer.width >= currentP.x && newPlayer.pos.x + newPlayer.width <= currentP.x + 15) {
            touchingWall = true;
            wallDirection = 1;
          } else if (newPlayer.pos.x <= currentP.x + currentP.width && newPlayer.pos.x >= currentP.x + currentP.width - 15) {
            touchingWall = true;
            wallDirection = -1;
          }
        }

        return currentP;
      });

      const moveInput = (keys.current['KeyW'] ? 1 : 0) - (keys.current['KeyS'] ? 1 : 0);
      if (moveInput !== 0) {
        newPlayer.vel.x += moveInput * config.moveSpeed;
      } else {
        newPlayer.vel.x *= currentFriction;
      }

      const maxS = config.maxSpeed * (newPlayer.vel.x > 18 ? 2.5 : 1.25);
      newPlayer.vel.x = Math.max(-maxS, Math.min(maxS, newPlayer.vel.x));

      newPlayer.isGrounded = grounded;
      newPlayer.isWallSliding = touchingWall && !grounded && newPlayer.vel.y > 0;

      if (newPlayer.isWallSliding) {
        newPlayer.vel.y = Math.min(newPlayer.vel.y, 3.0);
      } else {
        newPlayer.vel.y += config.gravity;
      }

      newPlayer.pos.x += newPlayer.vel.x;
      newPlayer.pos.y += newPlayer.vel.y;

      if (keys.current['Space']) {
        if (newPlayer.isGrounded) {
          newPlayer.vel.y = config.jumpForce;
          newPlayer.isGrounded = false;
          keys.current['Space'] = false; 
        } else if (newPlayer.isWallSliding) {
          newPlayer.vel.y = config.jumpForce * 0.95;
          newPlayer.vel.x = -wallDirection * 11;
          keys.current['Space'] = false;
        }
      }

      const cameraX = prev.cameraX + ((newPlayer.pos.x - window.innerWidth * 0.35) - prev.cameraX) * 0.1;
      const targetCameraY = newPlayer.pos.y - window.innerHeight / 2;
      const cameraY = prev.cameraY + (targetCameraY - prev.cameraY) * 0.08;

      const meters = Math.max(prev.score, Math.floor(newPlayer.pos.x));

      if (newPlayer.pos.y > prev.cameraY + window.innerHeight + 700) {
        isGameOver = true;
        pendingEncouragementContext.current = `Fell at ${meters}m.`;
      }

      if (meters >= prev.targetMeters && !prev.isGameWon) {
        isGameWon = true;
        updatedCompletionCounts[prev.difficulty] += 1;
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedCompletionCounts));
        pendingEncouragementContext.current = `WON ${prev.difficulty}!`;
      }

      const filteredParticles = newParticles.map(part => ({
        ...part, x: part.x + part.vx, y: part.y + part.vy, life: part.life - 0.02
      })).filter(part => part.life > 0);

      return {
        ...prev,
        player: newPlayer,
        platforms: updatedPlatforms,
        particles: filteredParticles,
        cameraX,
        cameraY,
        score: meters,
        isGameOver,
        isGameWon,
        highSpeedMode: newPlayer.vel.x > 18,
        completionCounts: updatedCompletionCounts,
      };
    });
  }, [generatePlatforms]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      update();
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [update]);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-100 touch-none">
      <GameCanvas gameState={gameState} />
      <UIOverlay 
        score={gameState.score}
        isGameOver={gameState.isGameOver}
        isGameWon={gameState.isGameWon}
        isSelectingMode={gameState.isSelectingMode}
        targetMeters={gameState.targetMeters}
        encouragement={encouragement}
        completionCounts={gameState.completionCounts}
        onRestart={resetGame}
        onSelectMode={selectMode}
        onInput={setInput}
      />
    </div>
  );
};

export default App;

